```javascript
// services/api.ts
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.REACT_APP_SUPABASE_URL;
const supabaseKey = process.env.REACT_APP_SUPABASE_KEY;

if (!supabaseUrl || !supabaseKey) {
  throw new Error('Supabase URL or Key not found in environment variables.');
}

export const supabase = createClient(supabaseUrl, supabaseKey);

export async function addIngredient(ingredientData: {
  name: string;
  currentStock: number;
  criticalStock: number;
  unit: string;
  expiryDate: string;
}) {
  try {
    const { data, error } = await supabase
      .from('ingredients')
      .insert([
        {
          id: Date.now().toString(),
          name: ingredientData.name,
          current_stock: ingredientData.currentStock,
          critical_stock: ingredientData.criticalStock,
          unit: ingredientData.unit,
          expiry_date: ingredientData.expiryDate,
        },
      ])
      .select();

    if (error) {
      console.error('Error adding ingredient:', error);
      return { success: false, error: error.message };
    }

    if (data && data.length > 0) {
      console.log('Ingredient added successfully:', data[0]);
      return { success: true, data: data[0] };
    } else {
      console.warn('No data returned from the insert operation.');
      return { success: false, error: 'No data returned from insert.' };
    }
  } catch (error) {
    console.error('Unexpected error during ingredient addition:', error);
    return { success: false, error: 'An unexpected error occurred.' };
  }
}
```

