interface SupplierReportProps {
  ingredients: Ingredient[];
}

export const SupplierReport: React.FC<SupplierReportProps> = ({ ingredients }) => {
  const groupedIngredients = useMemo(() => {
    const groups: Record<string, Ingredient[]> = {};

    ingredients.forEach(ing => {
      const supplier = ing.supplierName?.trim() || 'Unassigned / Local Market';
      if (!groups[supplier]) {
        groups[supplier] = [];
      }
      groups[supplier].push(ing);
    });

    // Sort suppliers alphabetically
    return Object.keys(groups).sort().reduce((acc, key) => {
      acc[key] = groups[key];
      return acc;
    }, {} as Record<string, Ingredient[]>);
  }, [ingredients]);

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="flex items-center gap-4 border-b border-slate-200 dark:border-slate-700 pb-6">
        <div className="p-3 bg-teal-100 dark:bg-teal-900/30 rounded-xl text-teal-600 dark:text-teal-300">
          <Truck size={32} />
        </div>
        <div>
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white">Supplier-Wise Ingredients</h2>
          <p className="text-slate-500 dark:text-slate-400">Inventory breakdown grouped by vendors and suppliers</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {Object.entries(groupedIngredients).map(([supplier, items]) => (
          <div key={supplier} className="bg-white dark:bg-slate-800 rounded-xl shadow-md border border-slate-200 dark:border-slate-700 overflow-hidden flex flex-col h-full hover:shadow-lg transition-shadow">
            <div className="p-4 bg-slate-50 dark:bg-slate-700/50 border-b border-slate-200 dark:border-slate-600">
              <h3 className="font-bold text-lg text-slate-800 dark:text-white flex items-center gap-2 truncate" title={supplier}>
                <Truck size={18} className="text-slate-400 shrink-0" />
                {supplier}
              </h3>
              {items[0]?.supplierContact && (
                <p className="text-sm text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
                  <Phone size={14} /> {items[0].supplierContact}
                </p>
              )}
              <div className="mt-2 text-xs font-semibold text-slate-500 bg-slate-200 dark:bg-slate-700 px-2 py-1 rounded inline-block">
                {items.length} Items Supplied
              </div>
            </div>

            <div className="p-0 flex-1 overflow-y-auto max-h-[400px] custom-scrollbar">
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 dark:bg-slate-800 text-xs uppercase text-slate-500 sticky top-0 z-10 shadow-sm">
                  <tr>
                    <th className="px-4 py-2 bg-slate-50 dark:bg-slate-800">Item</th>
                    <th className="px-4 py-2 text-right bg-slate-50 dark:bg-slate-800">Stock</th>
                    <th className="px-4 py-2 text-right bg-slate-50 dark:bg-slate-800">Price</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                  {items.map(item => (
                    <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">
                      <td className="px-4 py-2 font-medium text-slate-700 dark:text-slate-300">
                        {item.name}
                      </td>
                      <td className="px-4 py-2 text-right text-slate-600 dark:text-slate-400 whitespace-nowrap">
                        {item.currentStock} <span className="text-xs text-slate-400">{item.unit}</span>
                      </td>
                       <td className="px-4 py-2 text-right text-slate-600 dark:text-slate-400">
