import React, { useState } from 'react';
import { Ingredient } from '../types';
import { Plus, Minus, Save, RefreshCw } from 'lucide-react';

interface StockManagerProps {
  ingredients: Ingredient[];
  onUpdateStock: (id: string, quantity: number, type: 'add' | 'subtract', supplier?: string) => void;
}

export const StockManager: React.FC<StockManagerProps> = ({ ingredients, onUpdateStock }) => {
  const [selectedId, setSelectedId] = useState('');
  const [quantity, setQuantity] = useState('');
  const [type, setType] = useState<'add' | 'subtract'>('add');
  const [supplier, setSupplier] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedId || !quantity) {
      alert("Please select an item and enter a quantity.");
      return;
    }

    // Parse quantity on submit
    const qty = parseFloat(quantity);
    if (isNaN(qty) || qty < 0) {
      alert("Please enter a valid quantity.");
      return;
    }

    onUpdateStock(selectedId, qty, type, supplier);

    // Reset form
    setQuantity('');
    setSupplier('');
    alert(`Stock ${type === 'add' ? 'added' : 'removed'} successfully.`);
  };

  return (
    <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-md border border-slate-200 dark:border-slate-700 mb-8 transition-colors">
      <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2">
        <RefreshCw size={20} className="text-blue-600 dark:text-blue-400"/> 
        Quick Stock Adjustment
      </h3>
      <form onSubmit={handleSubmit} className="flex flex-col xl:flex-row gap-4 items-end">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 w-full">
            <div className="w-full">
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1">Select Ingredient</label>
            <select
                value={selectedId}
                onChange={(e) => setSelectedId(e.target.value)}
                className="w-full border border-blue-200 dark:border-blue-800 rounded-lg shadow-sm focus:border-blue-500 focus:ring-blue-500 text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-900 font-medium py-2.5 [&>option]:bg-white [&>option]:text-slate-900 dark:[&>option]:bg-slate-900 dark:[&>option]:text-slate-200"
            >
                <option value="">-- Choose Item to Update --</option>
                {ingredients.map(i => (
                <option key={i.id} value={i.id}>
                    {i.name} (Current: {i.currentStock} {i.unit})
                </option>
                ))}
            </select>
            </div>

            <div className="w-full">
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1">Quantity</label>
            <input
                type="number"
                min="0"
                step="0.001"
                placeholder="0.000"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
                className="w-full border-slate-600 bg-slate-700 text-white placeholder-slate-400 rounded-lg shadow-sm focus:border-blue-400 focus:ring-blue-400 py-2.5 font-bold"
            />
            </div>

            <div className="w-full">
            <label className="block text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1">Vendor / Supplier (Optional)</label>
            <input
                type="text"
                placeholder="Name of supplier"
                value={supplier}
                onChange={(e) => setSupplier(e.target.value)}
                className="w-full border border-slate-300 dark:border-slate-600 rounded-lg shadow-sm focus:border-blue-500 focus:ring-blue-500 text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-900 py-2.5 text-sm"
            />
            </div>
        </div>

        <div className="flex bg-slate-100 dark:bg-slate-700 p-1 rounded-lg shrink-0 w-full md:w-auto">
           <button
             type="button"
             onClick={() => setType('add')}
             className={`flex-1 md:flex-none justify-center px-4 py-2 rounded-md text-sm font-bold transition-all flex items-center gap-2 ${
               type === 'add' 
                 ? 'bg-white dark:bg-slate-600 text-green-600 dark:text-green-400 shadow-sm ring-1 ring-black/5' 
                 : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
             }`}
           >
             <Plus size={16} /> Add
           </button>
           <button
             type="button"
             onClick={() => setType('subtract')}
             className={`flex-1 md:flex-none justify-center px-4 py-2 rounded-md text-sm font-bold transition-all flex items-center gap-2 ${
               type === 'subtract' 
                 ? 'bg-white dark:bg-slate-600 text-red-600 dark:text-red-400 shadow-sm ring-1 ring-black/5' 
                 : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
             }`}
           >
             <Minus size={16} /> Remove
           </button>
        </div>

        <button
          type="submit"
          className="w-full md:w-auto bg-blue-600 text-white px-6 py-2.5 rounded-lg hover:bg-blue-700 font-bold shadow-lg shadow-blue-200 dark:shadow-blue-900/50 flex items-center justify-center gap-2 shrink-0 transition-transform active:scale-95"
        >
          <Save size={18} /> Update
        </button>
      </form>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Office, Ingredient, UserRole } from '../types';
import { Archive, AlertCircle, Eye, CheckSquare, Square, Layers, X, Download, Edit2, Trash2, CheckCircle2, ArrowUpDown, ArrowUp, ArrowDown, Search } from 'lucide-react';
import { StockManager } from './StockManager';

interface InventoryMastersProps {
  offices: Office[];
  ingredients: Ingredient[];
  onUpdateStock: (id: string, quantity: number, type: 'add' | 'subtract', supplier?: string) => void;
  userRole: UserRole;
  onUpdateIngredient?: (id: string, updates: Partial<Ingredient>) => void;
  onDeleteIngredient?: (id: string) => void;
}

type SortKey = 'name' | 'currentStock' | 'minStockThreshold';

export const InventoryMasters: React.FC<InventoryMastersProps> = ({ 
  offices, 
  ingredients, 
  onUpdateStock, 
  userRole,
  onUpdateIngredient,
  onDeleteIngredient
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkQuantity, setBulkQuantity] = useState<string>('');
  const [bulkType, setBulkType] = useState<'add' | 'subtract'>('add');

  // Search State
  const [searchQuery, setSearchQuery] = useState('');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'name',
    direction: 'asc'
  });

  // Inline Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Ingredient>>({});

  // Filtering & Sorting Logic
  const sortedIngredients = useMemo(() => {
    // 1. Filter
    const filtered = ingredients.filter(ing => {
      if (!searchQuery) return true;
      const lowerQuery = searchQuery.toLowerCase();
      return (
        ing.name.toLowerCase().includes(lowerQuery) ||
        (ing.supplierName && ing.supplierName.toLowerCase().includes(lowerQuery))
      );
    });

    // 2. Sort
    filtered.sort((a, b) => {
      let aValue = a[sortConfig.key];
      let bValue = b[sortConfig.key];

      // Handle string comparison for names (case-insensitive)
      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue)
          : bValue.localeCompare(aValue);
      }

      // Handle numeric comparison
      if (sortConfig.direction === 'asc') {
        return (aValue as number) - (bValue as number);
      } else {
        return (bValue as number) - (aValue as number);
      }
    });
    return filtered;
  }, [ingredients, sortConfig, searchQuery]);

  const handleSort = (key: SortKey) => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
    if (sortConfig.key !== columnKey) return <ArrowUpDown size={14} className="ml-1 text-slate-400 opacity-50" />;
    return sortConfig.direction === 'asc' 
      ? <ArrowUp size={14} className="ml-1 text-blue-500" />
      : <ArrowDown size={14} className="ml-1 text-blue-500" />;
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleSelectAll = () => {
    if (selectedIds.length === sortedIngredients.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(sortedIngredients.map(i => i.id));
    }
  };

  const handleBulkUpdate = () => {
    const qty = Number(bulkQuantity);
    if (!qty || qty <= 0) {
      alert("Please enter a valid quantity.");
      return;
    }

    const confirmMessage = `Are you sure you want to ${bulkType === 'add' ? 'ADD' : 'REMOVE'} ${qty} ${selectedIds.length === 1 ? 'unit' : 'units'} for ${selectedIds.length} selected items?`;

    if (window.confirm(confirmMessage)) {
      selectedIds.forEach(id => {
        onUpdateStock(id, qty, bulkType);
      });
      setSelectedIds([]);
      setBulkQuantity('');
      alert("Bulk update completed successfully.");
    }
  };

  const handleExportCSV = () => {
    if (ingredients.length === 0) {
      alert("No inventory data to export.");
      return;
    }

    const headers = ["Item Name", "Unit", "Unit Price", "Supplier", "Contact", "Last Updated", "Current Stock", "Min Threshold", "Status"];

    const csvRows = ingredients.map(ing => {
      const lastUpdated = ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleString() : '-';
      const status = ing.currentStock <= ing.minStockThreshold ? 'Low Stock' : 'In Stock';
      return [
        `"${ing.name.replace(/"/g, '""')}"`,
        ing.unit,
        ing.unitPrice.toFixed(2),
        `"${(ing.supplierName || '').replace(/"/g, '""')}"`,
        `"${(ing.supplierContact || '').replace(/"/g, '""')}"`,
        `"${lastUpdated}"`,
        ing.currentStock,
        ing.minStockThreshold,
        status
      ].join(",");
    });

    const csvString = [headers.join(","), ...csvRows].join("\n");
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `inventory_master_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Editing Logic
  const handleEditClick = (ing: Ingredient) => {
    setEditingId(ing.id);
    setEditForm({
      name: ing.name,
      unit: ing.unit,
      unitPrice: ing.unitPrice,
      minStockThreshold: ing.minStockThreshold,
      supplierName: ing.supplierName,
      supplierContact: ing.supplierContact
    });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const handleSaveEdit = (id: string) => {
    if (onUpdateIngredient) {
      onUpdateIngredient(id, editForm);
    }
    setEditingId(null);
    setEditForm({});
  };

  const handleDeleteClick = (id: string, name: string) => {
    if (window.confirm(`Are you sure you want to PERMANENTLY delete "${name}"? This action cannot be undone.`)) {
      if (onDeleteIngredient) {
        onDeleteIngredient(id);
      }
    }
  };

  const handleEditChange = (field: keyof Ingredient, value: string | number) => {
    setEditForm(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

      {/* Stock Manager Component (Only for ADMIN) */}
      {userRole === 'ADMIN' ? (
        <StockManager ingredients={sortedIngredients} onUpdateStock={onUpdateStock} />
      ) : (
        <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-900/50 p-4 rounded-xl flex items-center gap-3 text-blue-700 dark:text-blue-300 shadow-md border-slate-200">
           <Eye size={20} />
           <p className="font-medium">You are in Viewer Mode. Stock adjustments are disabled.</p>
        </div>
      )}

      {/* Bulk Action Bar (Contextual) */}
      {selectedIds.length > 0 && userRole === 'ADMIN' && (
        <div className="bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-200 dark:border-indigo-800 p-4 rounded-xl shadow-md flex flex-col md:flex-row items-center justify-between gap-4 animate-fade-in">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 dark:bg-indigo-800 p-2 rounded-lg text-indigo-600 dark:text-indigo-300">
              <Layers size={20} />
            </div>
            <div>
              <h4 className="font-bold text-indigo-700 dark:text-indigo-300">Bulk Actions</h4>
              <p className="text-xs text-indigo-500 dark:text-indigo-400">{selectedIds.length} items selected</p>
            </div>
          </div>

          <div className="flex items-center gap-3 w-full md:w-auto">
             <div className="flex rounded-lg overflow-hidden border border-indigo-200 dark:border-indigo-700">
                <button
                  onClick={() => setBulkType('add')}
                  className={`px-3 py-2 text-sm font-bold ${bulkType === 'add' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-300'}`}
                >
                  Add
                </button>
                <button
                  onClick={() => setBulkType('subtract')}
                  className={`px-3 py-2 text-sm font-bold ${bulkType === 'subtract' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-300'}`}
                >
                  Remove
                </button>
             </div>

             <input
              type="number"
              placeholder="Qty"
              value={bulkQuantity}
              onChange={(e) => setBulkQuantity(e.target.value)}
              className="w-20 px-3 py-2 rounded-lg border border-indigo-200 dark:border-indigo-700 bg-white dark:bg-slate-900 text-sm focus:ring-2 focus:ring-indigo-500"
             />

             <button
              onClick={handleBulkUpdate}
              className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors shadow-sm"
             >
               Apply
             </button>

             <button 
              onClick={() => setSelectedIds([])}
              className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
              title="Clear Selection"
             >
               <X size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Main Table Card */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-slate-200 dark:border-slate-700 flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
            <div>
              <h3 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Archive className="text-blue-500" size={24} />
                Ingredients & Stock Master
              </h3>
              <p className="text-sm text-slate-500 dark:text-slate-400">
                Monitor current inventory levels, unit prices, and supplier details.
              </p>
            </div>

            <div className="flex flex-col sm:flex-row items-center gap-3 w-full xl:w-auto">
              {/* Search Bar */}
              <div className="relative w-full sm:w-64">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search size={16} className="text-slate-400" />
                </div>
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search items or suppliers..."
                  className="w-full pl-10 pr-4 py-2 text-sm bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-colors"
                />
              </div>

              <div className="flex items-center gap-3 w-full sm:w-auto">
                <button 
                  onClick={handleExportCSV}
                  className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-300 border border-slate-300 dark:border-slate-600 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                >
                  <Download size={16} /> Export CSV
                </button>
              </div>
            </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-700/50 border-b border-slate-100 dark:border-slate-700">
              <tr>
                {userRole === 'ADMIN' && (
                  <th className="px-6 py-4 w-10 text-center">
                    <button onClick={handleSelectAll} className="text-slate-400 hover:text-blue-500">
                      {selectedIds.length === sortedIngredients.length && sortedIngredients.length > 0 ? <CheckSquare size={18} /> : <Square size={18} />}
                    </button>
                  </th>
                )}
                <th 
                  className="px-6 py-4 font-semibold cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('name')}
                >
                  <div className="flex items-center">
                    Item Name <SortIcon columnKey="name" />
                  </div>
                </th>
                <th className="px-6 py-4 font-semibold">Unit</th>
                <th className="px-6 py-4 font-semibold">Supplier Details</th>
                <th className="px-6 py-4 font-semibold text-right">Last Updated</th>
                <th 
                  className="px-6 py-4 font-semibold text-right cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('currentStock')}
                >
                  <div className="flex items-center justify-end">
                    Current Stock <SortIcon columnKey="currentStock" />
                  </div>
                </th>
                <th 
                  className="px-6 py-4 font-semibold text-right cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('minStockThreshold')}
                >
                  <div className="flex items-center justify-end">
                    Min Threshold <SortIcon columnKey="minStockThreshold" />
                  </div>
                </th>
                <th className="px-6 py-4 font-semibold text-center">Status</th>
                {userRole === 'ADMIN' && <th className="px-6 py-4 font-semibold text-center">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {sortedIngredients.length === 0 ? (
                 <tr>
                   <td colSpan={userRole === 'ADMIN' ? 9 : 8} className="px-6 py-12 text-center text-slate-400">
                     <p className="text-lg font-medium">No ingredients found.</p>
                     {searchQuery && <p className="text-sm">Try adjusting your search terms.</p>}
                   </td>
                 </tr>
              ) : (
                sortedIngredients.map((ing) => {
                  const isLowStock = ing.currentStock <= ing.minStockThreshold;
                  const isSelected = selectedIds.includes(ing.id);
                  const isEditing = editingId === ing.id;

                  return (
                    <tr 
                      key={ing.id} 
                      className={`hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors ${isSelected ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''} ${isLowStock ? 'bg-red-50/30 dark:bg-red-900/10' : ''}`}
                    >
                      {userRole === 'ADMIN' && (
                        <td className="px-6 py-4 text-center">
                          <button onClick={() => handleToggleSelect(ing.id)} className={`${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-slate-500'}`}>
                            {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                          </button>
                        </td>
                      )}

                      <td className="px-6 py-4">
                        {isEditing ? (
                           <div className="space-y-2">
                              <input 
                                type="text" 
                                value={editForm.name} 
                                onChange={(e) => handleEditChange('name', e.target.value)}
                                className="w-full text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900 text-slate-900 dark:text-white"
                              />
                               <div className="flex items-center gap-2">
                                  <span className="text-xs text-slate-500">Price: ৳</span>
                                  <input 
                                    type="number" 
                                    step="0.01"
                                    value={editForm.unitPrice} 
                                    onChange={(e) => handleEditChange('unitPrice', Number(e.target.value))}
                                    className="w-24 text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                                  />
                               </div>
                           </div>
                        ) : (
                          <div>
                            <p className="font-bold text-slate-800 dark:text-white">{ing.name}</p>
                          </div>
                        )}
                      </td>

                      <td className="px-6 py-4 text-slate-600 dark:text-slate-300">
                        {isEditing ? (
                          <input 
                            type="text" 
                            value={editForm.unit} 
                            onChange={(e) => handleEditChange('unit', e.target.value)}
                            className="w-16 text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                          />
                        ) : (
                          ing.unit
                        )}
                      </td>

                      <td className="px-6 py-4 text-slate-500 text-xs">
                         {isEditing ? (
                           <div className="space-y-1">
                             <input 
                                type="text" 
                                placeholder="Name"
                                value={editForm.supplierName || ''} 
                                onChange={(e) => handleEditChange('supplierName', e.target.value)}
                                className="w-full border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                             />
                             <input 
                                type="text" 
                                placeholder="Contact"
                                value={editForm.supplierContact || ''} 
                                onChange={(e) => handleEditChange('supplierContact', e.target.value)}
                                className="w-full border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                             />
                           </div>
                         ) : (
                            ing.supplierName ? (
                              <div>
                                <p className="font-semibold text-slate-700 dark:text-slate-300">{ing.supplierName}</p>
                                <p className="text-slate-400">{ing.supplierContact}</p>
                              </div>
                            ) : <span className="text-slate-400 italic">N/A</span>
                         )}
                      </td>

                      <td className="px-6 py-4 text-right">
                         <div className="flex flex-col items-end">
                            <span className="text-xs font-mono text-slate-500 dark:text-slate-400">
                              {ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleDateString() : '-'}
                            </span>
                            <span className="text-[10px] text-slate-400">
                               {ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                            </span>
                         </div>
                      </td>

                      <td className="px-6 py-4 text-right font-bold text-slate-800 dark:text-white text-lg">
                        {ing.currentStock}
                      </td>

                      <td className="px-6 py-4 text-right text-slate-600 dark:text-slate-400">
                         {isEditing ? (
                          <input 
                            type="number" 
                            value={editForm.minStockThreshold} 
                            onChange={(e) => handleEditChange('minStockThreshold', Number(e.target.value))}
                            className="w-20 text-right text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                          />
                        ) : (
                          ing.minStockThreshold
                        )}
                      </td>

                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${
                          isLowStock 
                            ? 'bg-rose-100 text-rose-800 border-rose-200 dark:bg-rose-900/30 dark:text-rose-300 dark:border-rose-800' 
                            : 'bg-emerald-100 text-emerald-800 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800'
                        }`}>
                          {isLowStock ? (
                            <>
                              <AlertCircle size={12} className="mr-1" />
                              Low Stock
                            </>
                          ) : (
                            <>In Stock</>
                          )}
                        </span>
                      </td>

                      {userRole === 'ADMIN' && (
                        <td className="px-6 py-4 text-center">
                          {isEditing ? (
                            <div className="flex items-center justify-center gap-2">
                               <button 
                                  onClick={() => handleSaveEdit(ing.id)}
                                  className="p-1.5 bg-green-100 text-green-700 rounded hover:bg-green-200 transition-colors"
                                  title="Save"
                               >
                                 <CheckSquare size={16} />
                               </button>
                               <button 
                                  onClick={handleCancelEdit}
                                  className="p-1.5 bg-slate-100 text-slate-600 rounded hover:bg-slate-200 transition-colors"
                                  title="Cancel"
                               >
                                 <X size={16} />
                               </button>
                            </div>
                          ) : (
                            <div className="flex items-center justify-center gap-3">
                              <button 
                                onClick={() => handleEditClick(ing)}
                                className="text-blue-500 hover:text-blue-700 transition-colors"
                                title="Edit Details"
                              >
                                <Edit2 size={16} />
                              </button>
                              <button 
                                onClick={() => handleDeleteClick(ing.id, ing.name)}
                                className="text-slate-400 hover:text-red-500 transition-colors"
                                title="Delete Item"
                              >
                                <Trash2 size={16} />
                              </button>
                            </div>
                          )}
                        </td>
                      )}
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { DailyEntryForm } from './components/DailyEntryForm';
import { InventoryMasters } from './components/InventoryMasters';
import { AuditLog } from './components/AuditLog';
import { SystemSettings } from './components/SystemSettings';
import { Login } from './components/Login';
import { SupplierReport } from './components/SupplierReport';
import { OFFICES } from './constants';
import { DailyEntry, Ingredient, UserRole, ActivityLog } from './types';
import { Menu, Loader2, Database } from 'lucide-react';
import { api } from './services/api';

function App() {
  // Authentication State
  const [userRole, setUserRole] = useState<UserRole | null>(() => {
    return sessionStorage.getItem('userRole') as UserRole | null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Theme State
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  // App Data State
  const [entries, setEntries] = useState<DailyEntry[]>([]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [activityHistory, setActivityHistory] = useState<ActivityLog[]>([]);
  const [offices] = useState(OFFICES);

  const [isLoading, setIsLoading] = useState(true);
  const [dataError, setDataError] = useState<string | null>(null);
  const [isConnected, setIsConnected] = useState(false);

  // Helper to log activity
  const handleLogActivity = async (action: any, details: string, metadata?: any) => {
    const log: ActivityLog = {
      id: `log_${Date.now()}`,
      timestamp: new Date().toISOString(),
      userRole: userRole || 'SYSTEM',
      action,
      details,
      metadata
    };

    // Update local state
    setActivityHistory(prev => [log, ...prev]);

    // Send to DB
    try {
      await api.logActivity(log);
    } catch (e) {
      console.error("Failed to log activity", e);
    }
  };

  // Initial Data Load
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        // Try to seed first (only runs if empty)
        await api.seedDatabase();

        const [fetchedIngredients, fetchedEntries, fetchedLogs] = await Promise.all([
          api.getIngredients(),
          api.getEntries(),
          api.getActivityLogs()
        ]);

        setIngredients(fetchedIngredients);
        setEntries(fetchedEntries);
        setActivityHistory(fetchedLogs);
        setDataError(null);
        setIsConnected(true);
      } catch (err: any) {
        console.error("Failed to load data from Supabase", err);
        // Fallback or error message
        setDataError("Could not connect to database. Please check your internet connection.");
        setIsConnected(false);
      } finally {
        setIsLoading(false);
      }
    };

    if (userRole) {
      loadData();
    }
  }, [userRole]);

  // Handle Login
  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    sessionStorage.setItem('userRole', role);
    handleLogActivity('LOGIN', `User logged in as ${role}`);
  };

  const handleLogout = () => {
    handleLogActivity('LOGOUT', `User ${userRole} logged out`);
    setUserRole(null);
    sessionStorage.removeItem('userRole');
    setActiveTab('dashboard');
    setIsConnected(false);
  };

  // Add Entry
  const handleAddEntry = async (newEntry: DailyEntry) => {
    // Optimistic Update
    setEntries(prev => [newEntry, ...prev]); // Add to top

    // Update Ingredients State locally
    const updatedIngredients = ingredients.map(ing => {
      const consumed = newEntry.itemsConsumed.find(c => c.ingredientId === ing.id);
      if (consumed) {
        return {
          ...ing,
          currentStock: Math.max(0, ing.currentStock - consumed.quantity),
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    // Redirect to correct dashboard based on entry type
    if (newEntry.officeId === 'events_main') {
        setActiveTab('events');
    } else {
        setActiveTab('dashboard');
    }

    handleLogActivity('CREATE_ENTRY', `Added Cost Sheet for ${newEntry.date}. Total: ৳${newEntry.totalCost}`, { entryId: newEntry.id });

    // Background Sync
    try {
      await api.addEntry(newEntry);
      // Update stock in DB for each consumed item
      for (const item of newEntry.itemsConsumed) {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        if (ing) {
           const newStock = Math.max(0, ing.currentStock - item.quantity);
           await api.updateStock(ing.id, newStock);
        }
      }
    } catch (error) {
      console.error("Failed to sync new entry:", error);
      alert("Error saving to cloud. Data saved locally only.");
      setIsConnected(false);
    }
  };

  // Delete Entry
  const handleDeleteEntry = async (id: string) => {
    const entryToDelete = entries.find(e => e.id === id);
    if (!entryToDelete) return;

    // --- REVERT STOCK LOGIC ---
    // Create a copy of ingredients to update state
    const updatedIngredients = [...ingredients];

    // Iterate through consumed items and add them back to stock
    for (const item of entryToDelete.itemsConsumed) {
      const index = updatedIngredients.findIndex(i => i.id === item.ingredientId);
      if (index !== -1) {
        const ing = updatedIngredients[index];
        // Calculate new stock (Add back the consumed quantity)
        const newStock = Number((ing.currentStock + item.quantity).toFixed(3));

        // Update local array
        updatedIngredients[index] = {
          ...ing,
          currentStock: newStock,
          lastUpdated: new Date().toISOString()
        };

        // Sync Stock Reversion to DB
        try {
          await api.updateStock(ing.id, newStock);
        } catch (error) {
          console.error(`Failed to revert stock for ${ing.name}`, error);
        }
      }
    }

    // Update Ingredients State with reverted values
    setIngredients(updatedIngredients);

    // Remove the entry from the list
    setEntries(prev => prev.filter(e => e.id !== id));

    handleLogActivity('DELETE_ENTRY', `Deleted Cost Sheet for ${entryToDelete.date}. Stock reverted.`, { 
      deletedEntry: entryToDelete 
    });

    // Background Sync: Delete Entry
    try {
      await api.deleteEntry(id);
    } catch (error) {
      console.error("Failed to delete entry:", error);
      setIsConnected(false);
    }
  };

  // Restore Entry (Undo Delete)
  const handleRestoreEntry = async (restoredEntry: DailyEntry) => {
    if (entries.some(e => e.id === restoredEntry.id)) {
        alert("This entry already exists (it might have been restored already).");
        return;
    }

    if (!window.confirm(`Restore Cost Sheet for ${restoredEntry.date}? This will re-deduct items from stock.`)) {
        return;
    }

    // 1. Optimistic Add to List
    setEntries(prev => [restoredEntry, ...prev].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

    // 2. Consume Stock Again
    const updatedIngredients = ingredients.map(ing => {
      const consumed = restoredEntry.itemsConsumed.find(c => c.ingredientId === ing.id);
      if (consumed) {
        return {
          ...ing,
          currentStock: Math.max(0, ing.currentStock - consumed.quantity),
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    handleLogActivity('RESTORE_DATA', `Restored Cost Sheet for ${restoredEntry.date}. Stock re-deducted.`);

    // 3. Database Sync
    try {
        await api.restoreEntry(restoredEntry);
        // Deduct Stock in DB
        for (const item of restoredEntry.itemsConsumed) {
            const ing = ingredients.find(i => i.id === item.ingredientId);
            if (ing) {
               const newStock = Math.max(0, ing.currentStock - item.quantity);
               await api.updateStock(ing.id, newStock);
            }
        }
        alert("Entry restored successfully.");
    } catch (error) {
        console.error("Failed to restore entry:", error);
        alert("Failed to restore entry. Please check connection.");
        setIsConnected(false);
    }
  };

  // Stock Update
  const handleStockUpdate = async (id: string, quantity: number, type: 'add' | 'subtract', supplierName?: string) => {
    // Optimistic Update
    let newStockValue = 0;
    let itemName = '';

    const updatedIngredients = ingredients.map(ing => {
      if (ing.id === id) {
        itemName = ing.name;
        let newStock = ing.currentStock;
        if (type === 'add') {
          newStock += quantity;
        } else {
          newStock = Math.max(0, newStock - quantity);
        }
        newStockValue = Number(newStock.toFixed(3));

        return { 
          ...ing, 
          currentStock: newStockValue,
          supplierName: supplierName || ing.supplierName, // Update supplier if provided
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    const logDetails = `${type === 'add' ? 'Added' : 'Removed'} ${quantity} units for ${itemName}${supplierName ? ` (Supplier: ${supplierName})` : ''}`;
    handleLogActivity('UPDATE_STOCK', logDetails, { 
      ingredientId: id, quantity, type, supplier: supplierName 
    });

    // Background Sync
    try {
      await api.updateStock(id, newStockValue);
      // If supplier name was provided, update the master record for supplier
      if (supplierName) {
        await api.updateIngredientMaster(id, { supplierName });
      }
    } catch (error) {
      console.error("Failed to update stock:", error);
      setIsConnected(false);
    }
  };

  // Ingredient Master Update (Edit Details)
  const handleUpdateIngredient = async (id: string, updates: Partial<Ingredient>) => {
    // Optimistic Update
    const ingName = ingredients.find(i => i.id === id)?.name || 'Unknown Item';
    setIngredients(prev => prev.map(i => i.id === id ? { ...i, ...updates } : i));

    handleLogActivity('UPDATE_MASTER', `Updated master details for ${ingName}`, { updates });

    try {
      await api.updateIngredientMaster(id, updates);
    } catch (error) {
      console.error("Failed to update ingredient:", error);
      setIsConnected(false);
      // Revert optimization on error would ideally go here by fetching
    }
  };

  // Add New Ingredient
  const handleAddIngredient = async (newIngredient: Ingredient) => {
    // Optimistic Update with Sort
    setIngredients(prev => [...prev, newIngredient].sort((a, b) => a.name.localeCompare(b.name)));

    handleLogActivity('UPDATE_MASTER', `Added new ingredient: ${newIngredient.name}`, { newIngredient });

    try {
      await api.addIngredient(newIngredient);
    } catch (error) {
      console.error("Failed to add ingredient:", error);
      setIsConnected(false);
    }
  };

  // Ingredient Delete
  const handleDeleteIngredient = async (id: string) => {
    const ingName = ingredients.find(i => i.id === id)?.name || 'Unknown Item';
    // Optimistic Update
    setIngredients(prev => prev.filter(i => i.id !== id));

    handleLogActivity('UPDATE_MASTER', `Deleted ingredient: ${ingName}`, { deletedId: id });

    try {
      await api.deleteIngredient(id);
    } catch (error) {
      console.error("Failed to delete ingredient:", error);
      setIsConnected(false);
    }
  };

  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [activeTab]);

  return (
    <HashRouter>
      {!userRole ? (
        <Login onLogin={handleLogin} />
      ) : (
        <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 relative transition-colors duration-200">
          {/* Mobile Header */}
          <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-slate-900 text-white z-40 flex items-center px-4 shadow-md justify-between">
            <button 
              onClick={() => setIsMobileMenuOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors"
            >
              <Menu size={24} />
            </button>
            <span className="font-bold text-lg text-blue-400">ACI CANTEEN</span>
            <div className="w-8"></div>
          </div>

          {/* Mobile Overlay */}
          {isMobileMenuOpen && (
            <div 
              className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm transition-opacity"
              onClick={() => setIsMobileMenuOpen(false)}
            />
          )}

          <Sidebar 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            isCollapsed={isSidebarCollapsed}
            toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            isMobileOpen={isMobileMenuOpen}
            setIsMobileOpen={setIsMobileMenuOpen}
            isDarkMode={isDarkMode}
            toggleDarkMode={toggleDarkMode}
            onLogout={handleLogout}
            userRole={userRole}
            isConnected={isConnected}
          />

          {/* Main Content */}
          <main 
            className={`flex-1 transition-all duration-300 
              ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} 
              ml-0 
              pt-16 md:pt-8 p-4 md:p-8 
              overflow-y-auto h-screen w-full
            `}
          >
            <div className="max-w-7xl mx-auto">
              {isLoading ? (
                <div className="flex flex-col items-center justify-center h-[60vh] text-slate-500">
                  <Loader2 size={48} className="animate-spin text-blue-500 mb-4" />
                  <p className="text-lg font-medium">Connecting to Database...</p>
                  <p className="text-sm">Fetching stock and history</p>
                </div>
              ) : dataError ? (
                <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 p-8 rounded-xl text-center">
                  <Database size={48} className="mx-auto text-red-500 mb-4" />
                  <h3 className="text-xl font-bold text-red-700 dark:text-red-300 mb-2">Connection Error</h3>
                  <p className="text-slate-600 dark:text-slate-300 mb-4">{dataError}</p>
                  <p className="text-sm text-slate-500">Make sure you have run the SQL script in Supabase Dashboard.</p>
                </div>
              ) : (
                <>
                  {activeTab === 'dashboard' && (
                    <Dashboard 
                      title="Executive Dashboard"
                      entries={entries.filter(e => e.officeId !== 'events_main')} 
                      offices={offices} 
                      ingredients={ingredients} 
                      isDarkMode={isDarkMode}
                      userRole={userRole}
                      onDeleteEntry={handleDeleteEntry}
                      onViewMasterStock={() => setActiveTab('masters')}
                      targetPerHead={72.72}
                    />
                  )}

                  {activeTab === 'events' && (
                    <Dashboard 
                      title="Events Cost Report"
                      entries={entries.filter(e => e.officeId === 'events_main')} 
                      offices={offices} 
                      ingredients={ingredients} 
                      isDarkMode={isDarkMode}
                      userRole={userRole}
                      onDeleteEntry={handleDeleteEntry}
                      onViewMasterStock={() => setActiveTab('masters')}
                      // Events might have a different target per head, setting high for now
                      targetPerHead={150}
                    />
                  )}

                  {activeTab === 'entry' && userRole === 'ADMIN' && (
                    <DailyEntryForm 
                      offices={offices} 
                      ingredients={ingredients} 
                      onAddEntry={handleAddEntry} 
                    />
                  )}

                  {activeTab === 'masters' && (
                    <InventoryMasters 
                      offices={offices} 
                      ingredients={ingredients}
                      onUpdateStock={handleStockUpdate}
                      userRole={userRole}
                      onUpdateIngredient={handleUpdateIngredient}
                      onDeleteIngredient={handleDeleteIngredient}
                    />
                  )}

                  {activeTab === 'suppliers' && (
                    <SupplierReport ingredients={ingredients} />
                  )}

                  {activeTab === 'history' && userRole === 'ADMIN' && (
                    <AuditLog 
                      logs={activityHistory}
                      onRestoreEntry={handleRestoreEntry}
                    />
                  )}

                  {activeTab === 'settings' && (
                    <SystemSettings 
                      userRole={userRole} 
                      onAddIngredient={handleAddIngredient}
                    />
                  )}
                </>
              )}
            </div>
          </main>
        </div>
      )}
    </HashRouter>
  );
}

