}

export const SupplierReport: React.FC<SupplierReportProps> = ({ ingredients }) => {
  const [searchQuery, setSearchQuery] = useState('');

  // Helper for relative time (e.g., "2 days ago")
  const getRelativeTime = (dateString?: string) => {
    if (!dateString) return 'Never';
    const date = new Date(dateString);
    const now = new Date();
    const diffInSeconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (diffInSeconds < 60) return 'Just now';
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)}m ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)}h ago`;
    if (diffInSeconds < 604800) return `${Math.floor(diffInSeconds / 86400)}d ago`;
    return date.toLocaleDateString();
  };

  const { groups, stats } = useMemo(() => {
    const groups: Record<string, Ingredient[]> = {};
    let totalValue = 0;
    let totalItems = 0;
    let lowStockCount = 0;

    ingredients.forEach(ing => {
      const supplier = ing.supplierName?.trim() || 'Unassigned / Local Market';
      if (!groups[supplier]) {
        groups[supplier] = [];
      }
      groups[supplier].push(ing);

      const val = ing.currentStock * ing.unitPrice;
      totalValue += val;
      totalItems++;
      if (ing.currentStock <= ing.minStockThreshold) lowStockCount++;
    });

    // Sort suppliers alphabetically
    const sortedGroups = Object.keys(groups).sort().reduce((acc, key) => {
      acc[key] = groups[key];
      return acc;
    }, {} as Record<string, Ingredient[]>);

    return { 
      groups: sortedGroups, 
      stats: {
        totalSuppliers: Object.keys(groups).length,
        totalItems,
        totalValue,
        lowStockCount
      }
    };
  }, [ingredients]);

  const filteredGroups = useMemo(() => {
    if (!searchQuery) return groups;
    const lowerQuery = searchQuery.toLowerCase();

    return Object.keys(groups).reduce((acc: Record<string, Ingredient[]>, key) => {
      // Filter by supplier name OR by ingredient name within that supplier
      const supplierMatch = key.toLowerCase().includes(lowerQuery);
      const matchingIngredients = groups[key].filter(i => i.name.toLowerCase().includes(lowerQuery));

