                        <thead className="text-xs text-slate-400 bg-white dark:bg-slate-800 uppercase border-b border-slate-100 dark:border-slate-700">
                            <tr>
                                <th className="px-5 py-3 font-semibold pl-6">Item Name</th>
                                <th className="px-5 py-3 text-right">Price</th>
                                <th className="px-5 py-3 text-center">Stock</th>
