                                        <span className="text-slate-600 dark:text-slate-400 font-medium">৳{item.unitPrice.toFixed(0)}</span>
                                    </td>

                                    <td className="px-5 py-3 text-center">
                                         {isLowStock ? (
                                             <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-xs font-bold border border-red-100 dark:border-red-900/50">
                                                <AlertCircle size={10} /> {item.currentStock}
                                             </span>
                                         ) : (
                                             <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 text-xs font-bold border border-emerald-100 dark:border-emerald-900/50">
                                                <CheckCircle2 size={10} /> {item.currentStock}
                                             </span>
                                         )}
                                    </td>

                                    <td className="px-5 py-3 text-right pr-6">
                                        <div className="flex flex-col items-end">
                                            {item.lastUpdated ? (
                                                <>
                                                    <span className="flex items-center gap-1.5 text-xs font-semibold text-slate-700 dark:text-slate-300 bg-slate-100 dark:bg-slate-700/50 px-2 py-1 rounded">
                                                        <Calendar size={10} />
                                                        {new Date(item.lastUpdated).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: '2-digit' })}
                                                    </span>
                                                    <span className="text-[10px] text-slate-400 mt-1 flex items-center gap-1">
