                                            {new Date(tx.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: '2-digit' })}
                                        </div>
                                        <div className="text-[10px] text-slate-400 mt-0.5 ml-4">
                                            {new Date(tx.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                        </div>
