  onAddEntry: (entry: DailyEntry) => void;
}

// Local interface for form inputs (handling strings for better UX)
interface ConsumptionItemInput {
  ingredientId: string;
  quantity: string;
  remarks: string;
  customRate: string;
}

export const DailyEntryForm: React.FC<DailyEntryFormProps> = ({ offices, ingredients, onAddEntry }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedOfficeId, setSelectedOfficeId] = useState(offices[0]?.id || '');
  const [menuDescription, setMenuDescription] = useState('');
  const [participants, setParticipants] = useState<number | ''>('');
  const [stockRemarks, setStockRemarks] = useState('');

  // Local state for the items being added (using strings for inputs)
  const [consumedItems, setConsumedItems] = useState<ConsumptionItemInput[]>([
    { ingredientId: '', quantity: '', remarks: '', customRate: '' }
  ]);

  const handleAddItemRow = () => {
    setConsumedItems([...consumedItems, { ingredientId: '', quantity: '', remarks: '', customRate: '' }]);
  };

  const handleRemoveItemRow = (index: number) => {
    const newItems = [...consumedItems];
    newItems.splice(index, 1);
    setConsumedItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof ConsumptionItemInput, value: string) => {
    const newItems = [...consumedItems];
    newItems[index] = { ...newItems[index], [field]: value };

    // Special logic: When ingredient changes, set the default customRate from master list
    if (field === 'ingredientId') {
      const selectedIng = ingredients.find(i => i.id === value);
      if (selectedIng) {
        newItems[index].customRate = selectedIng.unitPrice.toString();
      }
    }

    setConsumedItems(newItems);
  };

  const calculateTotalCost = () => {
    return consumedItems.reduce((total, item) => {
      // Use customRate if available (it should be set on selection), fallback to master list, then 0
      const masterPrice = ingredients.find(i => i.id === item.ingredientId)?.unitPrice ?? 0;
      // Parse float, defaulting to 0 if empty or invalid
      const itemRate = item.customRate !== '' ? parseFloat(item.customRate) : masterPrice;
      const quantity = parseFloat(item.quantity) || 0;

      return total + (itemRate * quantity);
    }, 0);
  };

  const totalCost = calculateTotalCost();
  const perPersonCost = participants ? totalCost / Number(participants) : 0;
  const selectedOfficeName = offices.find(o => o.id === selectedOfficeId)?.name || 'Unknown Office';

  const handleExportCSV = () => {
    const csvRows = [];

    // Metadata
    csvRows.push(['Cost Sheet Details']);
    csvRows.push(['Date', date]);
    csvRows.push(['Office', selectedOfficeName]);
    csvRows.push(['Menu', `"${menuDescription.replace(/"/g, '""')}"`]);
    csvRows.push(['Stock Remarks', `"${stockRemarks.replace(/"/g, '""')}"`]);
    csvRows.push([]);

    // Summary
    csvRows.push(['Summary']);
    csvRows.push(['Total Cost', totalCost.toFixed(2)]);
    csvRows.push(['Total Participants', participants]);
    csvRows.push(['Per Person Cost', perPersonCost.toFixed(2)]);
    csvRows.push([]);

    // Items Header
    csvRows.push(['SL', 'Item Name', 'Unit', 'Quantity', 'Rate', 'Amount', 'Remarks']);

    // Items Data
    consumedItems.forEach((item, index) => {
      const selectedIng = ingredients.find(i => i.id === item.ingredientId);
      const itemName = selectedIng ? selectedIng.name : '';
      const unit = selectedIng ? selectedIng.unit : '';

      const masterPrice = selectedIng?.unitPrice ?? 0;
      const rate = item.customRate !== '' ? parseFloat(item.customRate) : masterPrice;
      const quantity = parseFloat(item.quantity) || 0;
      const amount = rate * quantity;
      const remarks = item.remarks || '';

      csvRows.push([
        index + 1,
        `"${itemName.replace(/"/g, '""')}"`,
        unit,
        quantity,
        rate.toFixed(2),
        amount.toFixed(2),
        `"${remarks.replace(/"/g, '""')}"`
      ]);
    });

    const csvContent = csvRows.map(e => e.join(',')).join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `ACI_Cost_Sheet_${selectedOfficeName.replace(/\s+/g, '_')}_${date}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!participants) {
      alert("Please enter participant count.");
      return;
    }

    // Convert string inputs to typed objects and filter empty rows
    const validItems: ConsumptionItem[] = consumedItems
      .map(item => ({
        ingredientId: item.ingredientId,
        quantity: parseFloat(item.quantity) || 0,
        remarks: item.remarks,
        customRate: item.customRate !== '' ? parseFloat(item.customRate) : undefined
      }))
      .filter(item => item.ingredientId && item.quantity > 0);

    if (validItems.length === 0) {
      alert("Please add at least one item with quantity.");
      return;
    }

    const newEntry: DailyEntry = {
      id: `${Date.now()}`,
      date,
      officeId: selectedOfficeId,
      participantCount: Number(participants),
      itemsConsumed: validItems,
      totalCost: Number(totalCost.toFixed(2)),
      menuDescription,
      stockRemarks
    };
    onAddEntry(newEntry);

    // Reset form
    setMenuDescription('');
    setParticipants('');
    setStockRemarks('');
    setConsumedItems([{ ingredientId: '', quantity: '', remarks: '', customRate: '' }]);
    alert("Cost Sheet Saved Successfully!");
  };

  return (
    <div className="max-w-5xl mx-auto animate-fade-in pb-10">
      <div className="bg-white dark:bg-slate-800 shadow-xl border border-slate-200 dark:border-slate-700 rounded-lg overflow-hidden print:shadow-none print:border-none transition-colors">

        {/* Header Section */}
        <div className="border-b border-slate-300 dark:border-slate-600">
          <div className="py-4 text-center border-b border-slate-200 dark:border-slate-600">
            <h1 className="text-xl md:text-2xl font-bold text-slate-900 dark:text-white uppercase tracking-wide">Cost Sheet Entry</h1>
          </div>

          {/* Menu Bar (Light Blue) */}
          <div className="bg-cyan-50 dark:bg-cyan-900/30 px-4 md:px-8 py-3 border-b border-slate-200 dark:border-slate-600 flex flex-col md:flex-row items-start md:items-center gap-2 md:gap-4 transition-colors">
            <label htmlFor="menuInput" className="font-bold text-slate-700 dark:text-slate-300 underline shrink-0 cursor-pointer">Menu:</label>
            <textarea 
              id="menuInput"
              value={menuDescription}
              onChange={(e) => setMenuDescription(e.target.value)}
              placeholder="e.g., 1. Miniket Rice 2. Rui Fish 3. Mix Vegetable..."
              className="w-full bg-white dark:bg-slate-900 border border-cyan-200 dark:border-cyan-800 rounded-md px-3 py-1.5 focus:ring-2 focus:ring-blue-500 text-slate-800 dark:text-slate-200 placeholder-slate-400 font-medium shadow-sm transition-all resize-y min-h-[42px]"
              rows={1}
            />
          </div>

          <div className="py-3 text-center bg-white dark:bg-slate-800 border-b border-slate-200 dark:border-slate-600">
            <h2 className="text-sm md:text-lg font-bold text-slate-800 dark:text-slate-200">ACI Center - Daily Consumption</h2>
          </div>

          {/* Date & Location Row */}
          <div className="flex flex-col md:flex-row border-b border-slate-200 dark:border-slate-600 divide-y md:divide-y-0 md:divide-x divide-slate-200 dark:divide-slate-600">
            <div className="flex-1 p-4 flex items-center gap-3">
              <Calendar className="text-slate-500 dark:text-slate-400" size={18} />
              <label className="font-bold text-slate-700 dark:text-slate-300 w-16">Date:</label>
              <input 
                type="date" 
                value={date}
                onChange={(e) => setDate(e.target.value)}
                onClick={(e) => {
                  try {
                    (e.target as HTMLInputElement).showPicker?.();
                  } catch (error) {
                    // Fallback or ignore if not supported
                  }
                }}
                className="flex-1 bg-white dark:bg-slate-900 text-slate-900 dark:text-white border-slate-300 dark:border-slate-600 rounded-md shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
              />
            </div>
            <div className="flex-1 p-4 flex items-center gap-3">
              <MapPin className="text-slate-500 dark:text-slate-400" size={18} />
              <label className="font-bold text-slate-700 dark:text-slate-300 w-16">Office:</label>
              <select
                value={selectedOfficeId}
                onChange={(e) => setSelectedOfficeId(e.target.value)}
                className="flex-1 bg-white dark:bg-slate-900 text-slate-900 dark:text-white border-slate-300 dark:border-slate-600 rounded-md shadow-sm focus:border-blue-500 focus:ring-blue-500 p-2 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors font-medium"
              >
                {offices.map(office => (
                  <option key={office.id} value={office.id}>
                    {office.name}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Form Body */}
        <form onSubmit={handleSubmit}>
          {/* Desktop Table View */}
          <div className="hidden md:block overflow-x-auto">
            <table className="w-full text-sm text-left min-w-[800px]">
              <thead className="text-xs font-bold text-slate-700 dark:text-slate-300 uppercase bg-slate-200 dark:bg-slate-700 border-b border-slate-300 dark:border-slate-600">
                <tr>
                  <th className="px-4 py-3 w-12 text-center border-r border-slate-300 dark:border-slate-600">SL</th>
                  <th className="px-4 py-3 border-r border-slate-300 dark:border-slate-600">Items</th>
                  <th className="px-4 py-3 w-24 text-center border-r border-slate-300 dark:border-slate-600">Unit</th>
                  <th className="px-4 py-3 w-32 text-center border-r border-slate-300 dark:border-slate-600">Quantity</th>
                  <th className="px-4 py-3 w-32 text-right border-r border-slate-300 dark:border-slate-600">Rate (৳)</th>
                  <th className="px-4 py-3 w-32 text-right border-r border-slate-300 dark:border-slate-600">Amount (৳)</th>
                  <th className="px-4 py-3 w-48 border-r border-slate-300 dark:border-slate-600">Remarks</th>
                  <th className="px-2 py-3 w-10 text-center"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200 dark:divide-slate-600">
                {consumedItems.map((item, index) => {
                  const selectedIng = ingredients.find(i => i.id === item.ingredientId);

                  const masterPrice = selectedIng?.unitPrice ?? 0;
                  const rate = item.customRate !== '' ? parseFloat(item.customRate) : masterPrice;
                  const quantity = parseFloat(item.quantity) || 0;
                  const amount = rate * quantity;

                  // Logic to check if rate should be editable (Mixed Veg)
                  const isVegetableMixed = selectedIng?.name === 'Vegetable (Mixed)';

                  return (
                    <tr key={index} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">
                      <td className="px-4 py-2 text-center border-r border-slate-200 dark:border-slate-600 font-medium text-slate-500 dark:text-slate-400">
                        {index + 1}
                      </td>
                      <td className="px-4 py-2 border-r border-slate-200 dark:border-slate-600">
                        <select 
                          value={item.ingredientId}
                          onChange={e => handleItemChange(index, 'ingredientId', e.target.value)}
                          className="w-full border-0 bg-transparent focus:ring-0 text-slate-800 dark:text-slate-200 p-0 font-medium cursor-pointer [&>option]:bg-white [&>option]:text-slate-900 dark:[&>option]:bg-slate-800 dark:[&>option]:text-slate-200"
                        >
                          <option value="" disabled>Select Item...</option>
                          {ingredients.map(ing => (
                            <option key={ing.id} value={ing.id}>{ing.name}</option>
                          ))}
                        </select>
                      </td>
                      <td className="px-4 py-2 text-center border-r border-slate-200 dark:border-slate-600 text-slate-500 dark:text-slate-400">
                        {selectedIng?.unit || '-'}
                      </td>
                      <td className="px-4 py-2 border-r border-slate-200 dark:border-slate-600">
                        <input 
                          type="number"
                          min="0"
                          step="0.001"
                          placeholder="0.000"
                          value={item.quantity}
                          onChange={e => handleItemChange(index, 'quantity', e.target.value)}
                          className="w-full bg-white dark:bg-slate-900 text-slate-900 dark:text-white text-center border border-slate-200 dark:border-slate-600 rounded px-2 py-1 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                        />
                      </td>
                      <td className="px-4 py-2 text-right border-r border-slate-200 dark:border-slate-600 text-slate-600 dark:text-slate-300">
                        {isVegetableMixed ? (
                          <input 
                            type="number" 
                            min="0"
                            step="0.01"
                            value={item.customRate}
                            onChange={e => handleItemChange(index, 'customRate', e.target.value)}
                            className="w-full bg-white dark:bg-slate-900 text-slate-900 dark:text-white text-right border border-slate-200 dark:border-slate-600 rounded px-2 py-1 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 font-semibold"
                          />
                        ) : (
                          selectedIng ? `৳${rate.toFixed(2)}` : '-'
                        )}
                      </td>
                      <td className="px-4 py-2 text-right border-r border-slate-200 dark:border-slate-600 font-semibold text-slate-800 dark:text-slate-200">
                        {amount > 0 ? `৳${amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}` : '-'}
                      </td>
                      <td className="px-4 py-2 border-r border-slate-200 dark:border-slate-600">
                         <textarea 
                          value={item.remarks}
                          onChange={e => handleItemChange(index, 'remarks', e.target.value)}
                          className="w-full border-0 bg-transparent focus:ring-0 text-slate-600 dark:text-slate-300 p-0 text-sm resize-y min-h-[30px]"
                          placeholder="..."
                          rows={1}
                        />
                      </td>
                      <td className="px-2 py-2 text-center">
                        <button 
                          type="button" 
                          onClick={() => handleRemoveItemRow(index)}
                          className="text-slate-400 hover:text-red-500 transition-colors"
                          tabIndex={-1}
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {/* Mobile Card View */}
          <div className="md:hidden space-y-4 p-4 bg-slate-50 dark:bg-slate-900/50">
             {consumedItems.map((item, index) => {
               const selectedIng = ingredients.find(i => i.id === item.ingredientId);
               const masterPrice = selectedIng?.unitPrice ?? 0;
               const rate = item.customRate !== '' ? parseFloat(item.customRate) : masterPrice;
               const quantity = parseFloat(item.quantity) || 0;
               const amount = rate * quantity;
               const isVegetableMixed = selectedIng?.name === 'Vegetable (Mixed)';

               return (
                 <div key={index} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 space-y-3 relative">
                    <div className="flex justify-between items-start">
                        <div className="bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400 text-xs font-bold px-2 py-1 rounded">
                           #{index + 1}
                        </div>
                        <button 
                          type="button" 
                          onClick={() => handleRemoveItemRow(index)}
                          className="text-slate-400 hover:text-red-500 p-1 bg-slate-50 dark:bg-slate-700/50 rounded-full"
                        >
                          <X size={16} />
                        </button>
                    </div>

                    <div className="space-y-1">
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Ingredient</label>
                       <select 
                          value={item.ingredientId}
                          onChange={e => handleItemChange(index, 'ingredientId', e.target.value)}
                          className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-2.5 text-sm font-medium text-slate-800 dark:text-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        >
                          <option value="" disabled>Select Item...</option>
                          {ingredients.map(ing => (
                            <option key={ing.id} value={ing.id}>{ing.name}</option>
                          ))}
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                       <div className="space-y-1">
                          <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Qty ({selectedIng?.unit || '-'})</label>
                          <input 
                            type="number"
                            min="0"
                            step="0.001"
                            placeholder="0.00"
                            value={item.quantity}
                            onChange={e => handleItemChange(index, 'quantity', e.target.value)}
                            className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-2.5 text-sm font-bold text-center text-slate-800 dark:text-slate-200 focus:ring-2 focus:ring-blue-500"
                          />
                       </div>
                       <div className="space-y-1">
                          <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Rate (৳)</label>
                           {isVegetableMixed ? (
                              <input 
                                type="number" 
                                min="0"
                                step="0.01"
                                value={item.customRate}
                                onChange={e => handleItemChange(index, 'customRate', e.target.value)}
                                className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-2.5 text-sm font-bold text-right text-slate-800 dark:text-slate-200 focus:ring-2 focus:ring-blue-500"
                              />
                            ) : (
                              <div className="w-full bg-slate-100 dark:bg-slate-700/50 border border-transparent rounded-lg p-2.5 text-sm font-medium text-right text-slate-500 dark:text-slate-400">
                                 {selectedIng ? `৳${rate.toFixed(2)}` : '-'}
                              </div>
                            )}
                       </div>
                    </div>

                    <div className="space-y-1">
                       <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Remarks</label>
                       <textarea 
                          value={item.remarks}
                          onChange={e => handleItemChange(index, 'remarks', e.target.value)}
                          className="w-full bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg p-2.5 text-sm text-slate-800 dark:text-slate-200 focus:ring-2 focus:ring-blue-500 min-h-[60px]"
                          placeholder="Add optional notes..."
                          rows={2}
                        />
                    </div>

                    <div className="flex justify-between items-center pt-2 border-t border-slate-100 dark:border-slate-700">
                       <span className="text-xs font-bold text-slate-400 uppercase">Amount</span>
                       <span className="text-lg font-bold text-slate-800 dark:text-white">
                         {amount > 0 ? `৳${amount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}` : '-'}
                       </span>
                    </div>
                 </div>
               );
             })}
          </div>

          <div className="p-4 bg-slate-50 dark:bg-slate-700/50 border-t border-b border-slate-200 dark:border-slate-600 flex justify-center">
            <button 
              type="button" 
              onClick={handleAddItemRow}
              className="flex items-center gap-2 text-blue-600 dark:text-blue-400 font-semibold hover:text-blue-800 dark:hover:text-blue-300 hover:bg-blue-50 dark:hover:bg-blue-900/30 px-4 py-2 rounded transition-colors"
            >
              <Plus size={18} /> Add New Item Row
            </button>
          </div>

          {/* Footer Summary Section */}
          <div className="bg-white dark:bg-slate-800 transition-colors">
            <div className="flex flex-col items-end">
              {/* Total Costing */}
              <div className="w-full md:w-1/3 flex flex-row border-b border-slate-200 dark:border-slate-600">
                <div className="flex-1 py-3 px-4 md:px-6 text-right font-bold text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-700 border-l border-slate-200 dark:border-slate-600 text-sm md:text-base">
                  Total Costing
                </div>
                <div className="flex-1 py-3 px-4 md:px-6 text-right font-bold text-slate-900 dark:text-white text-sm md:text-base">
                  ৳{totalCost.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                </div>
              </div>

              {/* Total Participant */}
              <div className="w-full md:w-1/3 flex flex-row border-b border-slate-200 dark:border-slate-600">
                <div className="flex-1 py-3 px-4 md:px-6 text-right font-bold text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-700 border-l border-slate-200 dark:border-slate-600 text-sm md:text-base">
                  Total Participant
                </div>
                <div className="flex-1 py-2 px-4 md:px-6 text-right">
                  <input 
                    type="number"
                    min="1"
                    value={participants}
                    onChange={e => setParticipants(e.target.value === '' ? '' : Number(e.target.value))}
                    className="w-full md:w-24 bg-white dark:bg-slate-900 text-right font-bold text-slate-900 dark:text-white border border-slate-300 dark:border-slate-600 rounded px-2 py-1 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="0"
                  />
                </div>
              </div>

              {/* Per Person Costing */}
              <div className="w-full md:w-1/3 flex flex-row border-b border-slate-200 dark:border-slate-600">
                <div className="flex-1 py-3 px-4 md:px-6 text-right font-bold text-slate-700 dark:text-slate-300 bg-slate-50 dark:bg-slate-700 border-l border-slate-200 dark:border-slate-600 text-sm md:text-base">
                  Per Person Costing
                </div>
                <div className="flex-1 py-3 px-4 md:px-6 text-right font-bold text-blue-700 dark:text-blue-400 text-base md:text-lg">
                  ৳{perPersonCost.toFixed(2)}
                </div>
              </div>
            </div>

            {/* Stock / Bottom Note (Cyan Background) */}
            <div className="bg-cyan-50 dark:bg-cyan-900/30 border-t border-slate-200 dark:border-slate-600 p-4 flex flex-col md:flex-row items-start md:items-center gap-2 md:gap-4 transition-colors">
              <span className="font-bold text-lg md:text-xl text-slate-800 dark:text-slate-200 shrink-0">Stock:</span>
              <input 
                type="text" 
                value={stockRemarks}
                onChange={e => setStockRemarks(e.target.value)}
                placeholder="e.g. Egg 45 Pcs, Oil 2 Liters..."
                className="w-full bg-transparent border-b border-slate-400 dark:border-slate-500 focus:border-blue-600 dark:focus:border-blue-400 focus:ring-0 text-slate-800 dark:text-slate-200 text-base md:text-lg placeholder-slate-400 font-medium"
              />
            </div>
          </div>

          {/* Action Buttons */}
          <div className="p-6 bg-slate-50 dark:bg-slate-800 flex flex-col md:flex-row justify-end gap-4 border-t border-slate-200 dark:border-slate-600 rounded-b-lg">
            <button 
              type="button"
              onClick={handleExportCSV}
              className="w-full md:w-auto px-6 py-2.5 rounded-lg border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 font-medium hover:bg-white dark:hover:bg-slate-700 transition-colors flex items-center justify-center gap-2"
            >
              <Download size={18} />
              Export to CSV
            </button>
             <button 
              type="button"
              className="w-full md:w-auto px-6 py-2.5 rounded-lg border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 font-medium hover:bg-white dark:hover:bg-slate-700 transition-colors"
              onClick={() => {
                setConsumedItems([{ ingredientId: '', quantity: '', remarks: '', customRate: '' }]);
                setMenuDescription('');
                setStockRemarks('');
                setParticipants('');
              }}
            >
              Clear Form
            </button>
            <button 
              type="submit"
              className="w-full md:w-auto px-8 py-2.5 rounded-lg bg-blue-600 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 dark:shadow-blue-900/50 flex items-center justify-center gap-2 transition-transform active:scale-95"
            >
              <Save size={20} />
              Save Cost Sheet
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Office, Ingredient, UserRole } from '../types';
import { Archive, AlertCircle, Eye, CheckSquare, Square, Layers, X, Download, Edit2, Trash2, CheckCircle2, ArrowUpDown, ArrowUp, ArrowDown, Search } from 'lucide-react';
import { StockManager } from './StockManager';

interface InventoryMastersProps {
  offices: Office[];
  ingredients: Ingredient[];
  onUpdateStock: (id: string, quantity: number, type: 'add' | 'subtract', supplier?: string) => void;
  userRole: UserRole;
  onUpdateIngredient?: (id: string, updates: Partial<Ingredient>) => void;
  onDeleteIngredient?: (id: string) => void;
}

type SortKey = 'name' | 'currentStock' | 'minStockThreshold';

export const InventoryMasters: React.FC<InventoryMastersProps> = ({ 
  offices, 
  ingredients, 
  onUpdateStock, 
  userRole,
  onUpdateIngredient,
  onDeleteIngredient
}) => {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkQuantity, setBulkQuantity] = useState<string>('');
  const [bulkType, setBulkType] = useState<'add' | 'subtract'>('add');

  // Search State
  const [searchQuery, setSearchQuery] = useState('');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: 'asc' | 'desc' }>({
    key: 'name',
    direction: 'asc'
  });

  // Inline Editing State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<Ingredient>>({});

  // Delete Confirmation State
  const [deleteConfirmation, setDeleteConfirmation] = useState<{ id: string; name: string } | null>(null);

  // Filtering & Sorting Logic
  const sortedIngredients = useMemo(() => {
    // 1. Filter
    const filtered = ingredients.filter(ing => {
      if (!searchQuery) return true;
      const lowerQuery = searchQuery.toLowerCase();
      return (
        ing.name.toLowerCase().includes(lowerQuery) ||
        (ing.supplierName && ing.supplierName.toLowerCase().includes(lowerQuery))
      );
    });

    // 2. Sort
    filtered.sort((a, b) => {
      let aValue = a[sortConfig.key];
      let bValue = b[sortConfig.key];

      // Handle string comparison for names (case-insensitive)
      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue)
          : bValue.localeCompare(aValue);
      }

      // Handle numeric comparison
      if (sortConfig.direction === 'asc') {
        return (aValue as number) - (bValue as number);
      } else {
        return (bValue as number) - (aValue as number);
      }
    });
    return filtered;
  }, [ingredients, sortConfig, searchQuery]);

  const handleSort = (key: SortKey) => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
    if (sortConfig.key !== columnKey) return <ArrowUpDown size={14} className="ml-1 text-slate-400 opacity-50" />;
    return sortConfig.direction === 'asc' 
      ? <ArrowUp size={14} className="ml-1 text-blue-500" />
      : <ArrowDown size={14} className="ml-1 text-blue-500" />;
  };

  const handleToggleSelect = (id: string) => {
    setSelectedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleSelectAll = () => {
    if (selectedIds.length === sortedIngredients.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(sortedIngredients.map(i => i.id));
    }
  };

  const handleBulkUpdate = () => {
    const qty = Number(bulkQuantity);
    if (!qty || qty <= 0) {
      alert("Please enter a valid quantity.");
      return;
    }

    const confirmMessage = `Are you sure you want to ${bulkType === 'add' ? 'ADD' : 'REMOVE'} ${qty} ${selectedIds.length === 1 ? 'unit' : 'units'} for ${selectedIds.length} selected items?`;

    if (window.confirm(confirmMessage)) {
      selectedIds.forEach(id => {
        onUpdateStock(id, qty, bulkType);
      });
      setSelectedIds([]);
      setBulkQuantity('');
      alert("Bulk update completed successfully.");
    }
  };

  const handleExportCSV = () => {
    if (ingredients.length === 0) {
      alert("No inventory data to export.");
      return;
    }

    const headers = ["Item Name", "Unit", "Unit Price", "Supplier", "Contact", "Last Updated", "Current Stock", "Min Threshold", "Status"];

    const csvRows = ingredients.map(ing => {
      const lastUpdated = ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleString() : '-';
      const status = ing.currentStock <= ing.minStockThreshold ? 'Low Stock' : 'In Stock';
      return [
        `"${ing.name.replace(/"/g, '""')}"`,
        ing.unit,
        ing.unitPrice.toFixed(2),
        `"${(ing.supplierName || '').replace(/"/g, '""')}"`,
        `"${(ing.supplierContact || '').replace(/"/g, '""')}"`,
        `"${lastUpdated}"`,
        ing.currentStock,
        ing.minStockThreshold,
        status
      ].join(",");
    });

    const csvString = [headers.join(","), ...csvRows].join("\n");
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `inventory_master_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Editing Logic
  const handleEditClick = (ing: Ingredient) => {
    setEditingId(ing.id);
    setEditForm({
      name: ing.name,
      unit: ing.unit,
      unitPrice: ing.unitPrice,
      minStockThreshold: ing.minStockThreshold,
      supplierName: ing.supplierName,
      supplierContact: ing.supplierContact
    });
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditForm({});
  };

  const handleSaveEdit = (id: string) => {
    if (onUpdateIngredient) {
      onUpdateIngredient(id, editForm);
    }
    setEditingId(null);
    setEditForm({});
  };

  const handleDeleteClick = (id: string, name: string) => {
    setDeleteConfirmation({ id, name });
  };

  const confirmDelete = () => {
    if (deleteConfirmation && onDeleteIngredient) {
      onDeleteIngredient(deleteConfirmation.id);
    }
    setDeleteConfirmation(null);
  };

  const handleEditChange = (field: keyof Ingredient, value: string | number) => {
    setEditForm(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10">

      {/* Delete Confirmation Modal */}
      {deleteConfirmation && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-200 dark:border-slate-700">
            <div className="p-6 text-center">
              <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4">
                <AlertCircle size={32} className="text-red-600 dark:text-red-400" />
              </div>
              <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Delete Ingredient?</h3>
              <p className="text-slate-600 dark:text-slate-300 mb-6">
                Are you sure you want to permanently delete <span className="font-bold text-slate-900 dark:text-white">"{deleteConfirmation.name}"</span>?
                <br />
                <span className="text-sm text-red-500 mt-2 block font-medium">This action cannot be undone.</span>
              </p>

              <div className="flex justify-center gap-3">
                <button 
                  onClick={() => setDeleteConfirmation(null)}
                  className="px-5 py-2.5 rounded-lg border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-300 font-semibold hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={confirmDelete}
                  className="px-5 py-2.5 rounded-lg bg-red-600 hover:bg-red-700 text-white font-bold shadow-lg shadow-red-200 dark:shadow-red-900/30 transition-colors flex items-center gap-2"
                >
                  <Trash2 size={18} /> Delete Item
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Stock Manager Component (Only for ADMIN) */}
      {userRole === 'ADMIN' ? (
        <StockManager ingredients={sortedIngredients} onUpdateStock={onUpdateStock} />
      ) : (
        <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-900/50 p-4 rounded-xl flex items-center gap-3 text-blue-700 dark:text-blue-300 shadow-md border-slate-200">
           <Eye size={20} />
           <p className="font-medium">You are in Viewer Mode. Stock adjustments are disabled.</p>
        </div>
      )}

      {/* Bulk Action Bar (Contextual) */}
      {selectedIds.length > 0 && userRole === 'ADMIN' && (
        <div className="bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-200 dark:border-indigo-800 p-4 rounded-xl shadow-md flex flex-col md:flex-row items-center justify-between gap-4 animate-fade-in">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 dark:bg-indigo-800 p-2 rounded-lg text-indigo-600 dark:text-indigo-300">
              <Layers size={20} />
            </div>
            <div>
              <h4 className="font-bold text-indigo-700 dark:text-indigo-300">Bulk Actions</h4>
              <p className="text-xs text-indigo-500 dark:text-indigo-400">{selectedIds.length} items selected</p>
            </div>
          </div>

          <div className="flex items-center gap-3 w-full md:w-auto">
             <div className="flex rounded-lg overflow-hidden border border-indigo-200 dark:border-indigo-700">
                <button
                  onClick={() => setBulkType('add')}
                  className={`px-3 py-2 text-sm font-bold ${bulkType === 'add' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-300'}`}
                >
                  Add
                </button>
                <button
                  onClick={() => setBulkType('subtract')}
                  className={`px-3 py-2 text-sm font-bold ${bulkType === 'subtract' ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-slate-900 text-slate-600 dark:text-slate-300'}`}
                >
                  Remove
                </button>
             </div>

             <input
              type="number"
              placeholder="Qty"
              value={bulkQuantity}
              onChange={(e) => setBulkQuantity(e.target.value)}
              className="w-20 px-3 py-2 rounded-lg border border-indigo-200 dark:border-indigo-700 bg-white dark:bg-slate-900 text-sm focus:ring-2 focus:ring-indigo-500"
             />

             <button
              onClick={handleBulkUpdate}
              className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors shadow-sm"
             >
               Apply
             </button>

             <button 
              onClick={() => setSelectedIds([])}
              className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300"
              title="Clear Selection"
             >
               <X size={18} />
             </button>
          </div>
        </div>
      )}

      {/* Main Table Card */}
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-slate-200 dark:border-slate-700 flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
            <div>
              <h3 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Archive className="text-blue-500" size={24} />
                Ingredients & Stock Master
              </h3>
              <p className="text-sm text-slate-500 dark:text-slate-400">
                Monitor current inventory levels, unit prices, and supplier details.
              </p>
            </div>

            <div className="flex flex-col sm:flex-row items-center gap-3 w-full xl:w-auto">
              {/* Search Bar */}
              <div className="relative w-full sm:w-64">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search size={16} className="text-slate-400" />
                </div>
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Search items or suppliers..."
                  className="w-full pl-10 pr-4 py-2 text-sm bg-slate-50 dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-colors"
                />
              </div>

              <div className="flex items-center gap-3 w-full sm:w-auto">
                <button 
                  onClick={handleExportCSV}
                  className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-300 border border-slate-300 dark:border-slate-600 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                >
                  <Download size={16} /> Export CSV
                </button>
              </div>
            </div>
        </div>

        {/* Desktop Table */}
        <div className="hidden md:block overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-700/50 border-b border-slate-100 dark:border-slate-700">
              <tr>
                {userRole === 'ADMIN' && (
                  <th className="px-6 py-4 w-10 text-center">
                    <button onClick={handleSelectAll} className="text-slate-400 hover:text-blue-500">
                      {selectedIds.length === sortedIngredients.length && sortedIngredients.length > 0 ? <CheckSquare size={18} /> : <Square size={18} />}
                    </button>
                  </th>
                )}
                <th 
                  className="px-6 py-4 font-semibold cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('name')}
                >
                  <div className="flex items-center">
                    Item Name <SortIcon columnKey="name" />
                  </div>
                </th>
                <th className="px-6 py-4 font-semibold">Unit</th>
                <th className="px-6 py-4 font-semibold">Supplier Details</th>
                <th className="px-6 py-4 font-semibold text-right">Last Updated</th>
                <th 
                  className="px-6 py-4 font-semibold text-right cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('currentStock')}
                >
                  <div className="flex items-center justify-end">
                    Current Stock <SortIcon columnKey="currentStock" />
                  </div>
                </th>
                <th 
                  className="px-6 py-4 font-semibold text-right cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-700/50 transition-colors"
                  onClick={() => handleSort('minStockThreshold')}
                >
                  <div className="flex items-center justify-end">
                    Min Threshold <SortIcon columnKey="minStockThreshold" />
                  </div>
                </th>
                <th className="px-6 py-4 font-semibold text-center">Status</th>
                {userRole === 'ADMIN' && <th className="px-6 py-4 font-semibold text-center">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {sortedIngredients.length === 0 ? (
                 <tr>
                   <td colSpan={userRole === 'ADMIN' ? 9 : 8} className="px-6 py-12 text-center text-slate-400">
                     <p className="text-lg font-medium">No ingredients found.</p>
                     {searchQuery && <p className="text-sm">Try adjusting your search terms.</p>}
                   </td>
                 </tr>
              ) : (
                sortedIngredients.map((ing) => {
                  const isLowStock = ing.currentStock <= ing.minStockThreshold;
                  const isSelected = selectedIds.includes(ing.id);
                  const isEditing = editingId === ing.id;

                  return (
                    <tr 
                      key={ing.id} 
                      className={`hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors ${isSelected ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''} ${isLowStock ? 'bg-red-50/30 dark:bg-red-900/10' : ''}`}
                    >
                      {userRole === 'ADMIN' && (
                        <td className="px-6 py-4 text-center">
                          <button onClick={() => handleToggleSelect(ing.id)} className={`${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-slate-500'}`}>
                            {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                          </button>
                        </td>
                      )}

                      <td className="px-6 py-4">
                        {isEditing ? (
                           <div className="space-y-2">
                              <input 
                                type="text" 
                                value={editForm.name} 
                                onChange={(e) => handleEditChange('name', e.target.value)}
                                className="w-full text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900 text-slate-900 dark:text-white"
                              />
                               <div className="flex items-center gap-2">
                                  <span className="text-xs text-slate-500">Price: ৳</span>
                                  <input 
                                    type="number" 
                                    step="0.01"
                                    value={editForm.unitPrice} 
                                    onChange={(e) => handleEditChange('unitPrice', Number(e.target.value))}
                                    className="w-24 text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                                  />
                               </div>
                           </div>
                        ) : (
                          <div>
                            <p className="font-bold text-slate-800 dark:text-white">{ing.name}</p>
                          </div>
                        )}
                      </td>

                      <td className="px-6 py-4 text-slate-600 dark:text-slate-300">
                        {isEditing ? (
                          <input 
                            type="text" 
                            value={editForm.unit} 
                            onChange={(e) => handleEditChange('unit', e.target.value)}
                            className="w-16 text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                          />
                        ) : (
                          ing.unit
                        )}
                      </td>

                      <td className="px-6 py-4 text-slate-500 text-xs">
                         {isEditing ? (
                           <div className="space-y-1">
                             <input 
                                type="text" 
                                placeholder="Name"
                                value={editForm.supplierName || ''} 
                                onChange={(e) => handleEditChange('supplierName', e.target.value)}
                                className="w-full border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                             />
                             <input 
                                type="text" 
                                placeholder="Contact"
                                value={editForm.supplierContact || ''} 
                                onChange={(e) => handleEditChange('supplierContact', e.target.value)}
                                className="w-full border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                             />
                           </div>
                         ) : (
                            ing.supplierName ? (
                              <div>
                                <p className="font-semibold text-slate-700 dark:text-slate-300">{ing.supplierName}</p>
                                <p className="text-slate-400">{ing.supplierContact}</p>
                              </div>
                            ) : <span className="text-slate-400 italic">N/A</span>
                         )}
                      </td>

                      <td className="px-6 py-4 text-right">
                         <div className="flex flex-col items-end">
                            <span className="text-xs font-mono text-slate-500 dark:text-slate-400">
                              {ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleDateString() : '-'}
                            </span>
                            <span className="text-[10px] text-slate-400">
                               {ing.lastUpdated ? new Date(ing.lastUpdated).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ''}
                            </span>
                         </div>
                      </td>

                      <td className="px-6 py-4 text-right font-bold text-slate-800 dark:text-white text-lg">
                        {ing.currentStock}
                      </td>

                      <td className="px-6 py-4 text-right text-slate-600 dark:text-slate-400">
                         {isEditing ? (
                          <input 
                            type="number" 
                            value={editForm.minStockThreshold} 
                            onChange={(e) => handleEditChange('minStockThreshold', Number(e.target.value))}
                            className="w-20 text-right text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-white dark:bg-slate-900"
                          />
                        ) : (
                          ing.minStockThreshold
                        )}
                      </td>

                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${
                          isLowStock 
                            ? 'bg-rose-100 text-rose-800 border-rose-200 dark:bg-rose-900/30 dark:text-rose-300 dark:border-rose-800' 
                            : 'bg-emerald-100 text-emerald-800 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800'
                        }`}>
                          {isLowStock ? (
                            <>
                              <AlertCircle size={12} className="mr-1" />
                              Low Stock
                            </>
                          ) : (
                            <>In Stock</>
                          )}
                        </span>
                      </td>

                      {userRole === 'ADMIN' && (
                        <td className="px-6 py-4 text-center">
                          {isEditing ? (
                            <div className="flex items-center justify-center gap-2">
                               <button 
                                  onClick={() => handleSaveEdit(ing.id)}
                                  className="p-1.5 bg-green-100 text-green-700 rounded hover:bg-green-200 transition-colors"
                                  title="Save"
                               >
                                 <CheckSquare size={16} />
                               </button>
                               <button 
                                  onClick={handleCancelEdit}
                                  className="p-1.5 bg-slate-100 text-slate-600 rounded hover:bg-slate-200 transition-colors"
                                  title="Cancel"
                               >
                                 <X size={16} />
                               </button>
                            </div>
                          ) : (
                            <div className="flex items-center justify-center gap-3">
                              <button 
                                onClick={() => handleEditClick(ing)}
                                className="text-blue-500 hover:text-blue-700 transition-colors"
                                title="Edit Details"
                              >
                                <Edit2 size={16} />
                              </button>
                              <button 
                                onClick={() => handleDeleteClick(ing.id, ing.name)}
                                className="text-slate-400 hover:text-red-500 transition-colors"
                                title="Delete Item"
                              >
                                <Trash2 size={16} />
                              </button>
                            </div>
                          )}
                        </td>
                      )}
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>

        {/* Mobile Card List View */}
        <div className="md:hidden space-y-4 p-4 bg-slate-50 dark:bg-slate-900/50">
           {sortedIngredients.length === 0 ? (
             <div className="text-center py-10 text-slate-400">
               <p className="font-medium">No ingredients found.</p>
             </div>
           ) : (
             sortedIngredients.map(ing => {
               const isLowStock = ing.currentStock <= ing.minStockThreshold;
               const isSelected = selectedIds.includes(ing.id);
               const isEditing = editingId === ing.id;

               return (
                 <div key={ing.id} className={`bg-white dark:bg-slate-800 rounded-xl shadow-sm border p-4 transition-all relative ${
                    isLowStock ? 'border-red-200 dark:border-red-900' : 'border-slate-200 dark:border-slate-700'
                 }`}>
                    {/* Header: Name + Badge */}
                    <div className="flex justify-between items-start mb-3 pr-8">
                       <div>
                         {isEditing ? (
                           <div className="space-y-2 mb-2">
                              <input 
                                type="text" 
                                value={editForm.name} 
                                onChange={(e) => handleEditChange('name', e.target.value)}
                                className="w-full text-base font-bold border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-white"
                              />
                           </div>
                         ) : (
                           <h4 className="font-bold text-lg text-slate-900 dark:text-white">{ing.name}</h4>
                         )}
                         <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400">
                            {isEditing ? (
                               <input 
                                type="text" 
                                value={editForm.unit} 
                                onChange={(e) => handleEditChange('unit', e.target.value)}
                                className="w-16 text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-slate-50 dark:bg-slate-900"
                              />
                            ) : (
                               <span>Unit: {ing.unit}</span>
                            )}
                            <span>•</span>
                            {isEditing ? (
                              <div className="flex items-center gap-1">
                                <span>৳</span>
                                <input 
                                    type="number" 
                                    step="0.01"
                                    value={editForm.unitPrice} 
                                    onChange={(e) => handleEditChange('unitPrice', Number(e.target.value))}
                                    className="w-20 text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-slate-50 dark:bg-slate-900"
                                  />
                              </div>
                            ) : (
                               <span>৳{ing.unitPrice.toFixed(2)}</span>
                            )}
                         </div>
                       </div>
                    </div>

                    {/* Status Badge Absolute */}
                    <div className="absolute top-4 right-4">
                        <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${
                          isLowStock 
                            ? 'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-900/30 dark:text-rose-300 dark:border-rose-800' 
                            : 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800'
                        }`}>
                           {isLowStock ? 'Low Stock' : 'OK'}
                        </span>
                    </div>

                    {/* Checkbox for Bulk (Admin Only) */}
                    {userRole === 'ADMIN' && (
                       <button 
                         onClick={() => handleToggleSelect(ing.id)} 
                         className="absolute bottom-4 right-4 text-slate-400 p-2"
                       >
                         {isSelected ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                       </button>
                    )}

                    {/* Stock Grid */}
                    <div className="grid grid-cols-2 gap-4 my-3 bg-slate-50 dark:bg-slate-700/30 rounded-lg p-3">
                       <div>
                          <span className="text-xs font-bold text-slate-400 uppercase">Current</span>
                          <p className="text-xl font-bold text-slate-800 dark:text-white">{ing.currentStock}</p>
                       </div>
                       <div>
                          <span className="text-xs font-bold text-slate-400 uppercase">Min Limit</span>
                          {isEditing ? (
                             <input 
                                type="number" 
                                value={editForm.minStockThreshold} 
                                onChange={(e) => handleEditChange('minStockThreshold', Number(e.target.value))}
                                className="w-full text-sm border border-slate-300 dark:border-slate-600 rounded px-2 py-1 mt-1 bg-white dark:bg-slate-900"
                              />
                          ) : (
                             <p className="text-xl font-medium text-slate-600 dark:text-slate-300">{ing.minStockThreshold}</p>
                          )}
                       </div>
                    </div>

                    {/* Supplier Info */}
                    <div className="text-sm text-slate-500 dark:text-slate-400 mb-4">
                       {isEditing ? (
                          <div className="space-y-2">
                             <input 
                                type="text" 
                                placeholder="Supplier Name"
                                value={editForm.supplierName || ''} 
                                onChange={(e) => handleEditChange('supplierName', e.target.value)}
                                className="w-full text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-slate-50 dark:bg-slate-900"
                             />
                             <input 
                                type="text" 
                                placeholder="Contact Info"
                                value={editForm.supplierContact || ''} 
                                onChange={(e) => handleEditChange('supplierContact', e.target.value)}
                                className="w-full text-xs border border-slate-300 dark:border-slate-600 rounded px-2 py-1 bg-slate-50 dark:bg-slate-900"
                             />
                          </div>
                       ) : (
                          ing.supplierName ? (
                             <div className="flex flex-col">
                                <span className="font-semibold text-slate-700 dark:text-slate-300">{ing.supplierName}</span>
                                <span className="text-xs">{ing.supplierContact}</span>
                             </div>
                          ) : <span className="italic text-xs">No supplier info</span>
                       )}
                    </div>

                    {/* Actions */}
                    {userRole === 'ADMIN' && (
                       <div className="flex items-center gap-3 mt-4 pt-3 border-t border-slate-100 dark:border-slate-700/50">
                          {isEditing ? (
                            <>
                               <button 
                                  onClick={() => handleSaveEdit(ing.id)}
                                  className="flex-1 py-2 bg-green-600 text-white rounded-lg text-sm font-bold shadow-sm"
                               >
                                 Save
                               </button>
                               <button 
                                  onClick={handleCancelEdit}
                                  className="flex-1 py-2 bg-slate-200 text-slate-700 dark:bg-slate-700 dark:text-slate-300 rounded-lg text-sm font-bold"
                               >
                                 Cancel
                               </button>
                            </>
                          ) : (
                            <>
                               <button 
                                 onClick={() => handleEditClick(ing)}
                                 className="flex-1 py-2 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 rounded-lg text-sm font-medium hover:bg-slate-50 dark:hover:bg-slate-700"
                               >
                                 Edit
                               </button>
                               <button 
                                 onClick={() => handleDeleteClick(ing.id, ing.name)}
                                 className="flex-1 py-2 border border-red-200 dark:border-red-900/50 text-red-600 dark:text-red-400 rounded-lg text-sm font-medium hover:bg-red-50 dark:hover:bg-red-900/20"
                               >
                                 Delete
                               </button>
                            </>
                          )}
                       </div>
                    )}
                 </div>
               );
             })
           )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import { TrendingUp, Users, AlertTriangle, ArrowRight, Download, Filter, Calendar, Trash2, AlertCircle, BarChart3, Eye } from 'lucide-react';
import { DailyEntry, Office, Ingredient, UserRole } from '../types';
import { CostSheetDetailsModal } from './CostSheetDetailsModal';

interface DashboardProps {
  title?: string;
  entries: DailyEntry[];
  offices: Office[];
  ingredients: Ingredient[];
  isDarkMode?: boolean;
  userRole: UserRole;
  onDeleteEntry: (id: string) => void;
  onViewMasterStock?: () => void;
  targetPerHead?: number;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  title = "Executive Dashboard",
  entries, 
  offices, 
  ingredients, 
  isDarkMode, 
  userRole, 
  onDeleteEntry,
  onViewMasterStock,
  targetPerHead = 72.72
}) => {
  const [selectedMonth, setSelectedMonth] = useState<string>('last30');

  // State for viewing details modal
  const [selectedEntry, setSelectedEntry] = useState<DailyEntry | null>(null);

  // 1. Available Months for Filter
  const availableMonths = useMemo(() => {
    const months = new Set(entries.map(e => e.date.substring(0, 7))); // YYYY-MM
    return Array.from(months).sort().reverse();
  }, [entries]);

  // 2. Filter Data based on selection (Shared by Chart, KPI, and Table)
  const filteredEntries = useMemo(() => {
    const sortedEntries = [...entries].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    if (selectedMonth === 'last30') {
      // Return last 30 entries
      return sortedEntries.slice(-30);
    }
    // Return entries for the selected month
    return sortedEntries.filter(e => e.date.startsWith(selectedMonth));
  }, [entries, selectedMonth]);

  // 3. Calculate Average Metrics from filtered data
  const { avgDailyCost, avgPerHead, avgParticipants } = useMemo(() => {
    if (filteredEntries.length === 0) {
      return { avgDailyCost: 0, avgPerHead: 0, avgParticipants: 0 };
    }

    const totalCost = filteredEntries.reduce((sum, e) => sum + e.totalCost, 0);
    const totalParts = filteredEntries.reduce((sum, e) => sum + e.participantCount, 0);

    return {
      avgDailyCost: totalCost / filteredEntries.length,
      avgPerHead: totalParts > 0 ? totalCost / totalParts : 0, // Weighted Average
      avgParticipants: Math.round(totalParts / filteredEntries.length)
    };
  }, [filteredEntries]);

  // Check if average per head exceeds target
  const isAvgPerHeadHigh = avgPerHead > targetPerHead;

  // 4. Prepare Chart Data (using filteredEntries)
  const trendData = useMemo(() => {
    return filteredEntries.map((e) => {
      const perHead = e.participantCount > 0 ? e.totalCost / e.participantCount : 0;
      return {
        date: e.date.substring(5), // MM-DD
        CostPerHead: Number(perHead.toFixed(2)),
        TotalCost: e.totalCost
      };
    });
  }, [filteredEntries]);

  // 5. Monthly Aggregation Data (Yearly View)
  const monthlyCostData = useMemo(() => {
    // Determine the year to display (from data, or current year)
    // Using 2025 as default based on the dataset provided
    const targetYear = 2025; 

    const monthlyTotals: Record<number, number> = {};

    entries.forEach(entry => {
      const date = new Date(entry.date);
      if (date.getFullYear() === targetYear) {
        const monthIndex = date.getMonth(); // 0-11
        monthlyTotals[monthIndex] = (monthlyTotals[monthIndex] || 0) + entry.totalCost;
      }
    });

    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

    return monthNames.map((name, index) => ({
      name,
      total: monthlyTotals[index] || 0
    })).filter(item => item.total > 0); // Only show months with data
  }, [entries]);

  // 6. Stock Alerts
  const lowStockItems = ingredients.filter(i => i.currentStock <= i.minStockThreshold);

  // 7. Displayed Entries for Table (Descending Order)
  const displayedEntries = useMemo(() => {
    return [...filteredEntries].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredEntries]);

  const handleExportCSV = () => {
    if (displayedEntries.length === 0) {
      alert("No data available to export.");
      return;
    }

    // CSV Headers
    const headers = ["Date", "Participants", "Total Cost", "Per Head Cost", "Menu Description"];

    // Generate CSV Rows
    const csvRows = displayedEntries.map(entry => {
      const perHead = entry.participantCount > 0 ? (entry.totalCost / entry.participantCount).toFixed(2) : "0.00";
      // Escape quotes in menu description and wrap in quotes
      const menu = entry.menuDescription ? `"${entry.menuDescription.replace(/"/g, '""')}"` : '""';

      return [
        entry.date,
        entry.participantCount,
        entry.totalCost.toFixed(2),
        perHead,
        menu
      ].join(",");
    });

    // Combine headers and rows
    const csvString = [headers.join(","), ...csvRows].join("\n");

    // Create Blob and trigger download
    const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `report_${selectedMonth === 'last30' ? 'last30days' : selectedMonth}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const formatMonth = (monthStr: string) => {
    const [year, month] = monthStr.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1);
    return date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
  };

  const handleDeleteClick = (id: string, date: string) => {
    if (window.confirm(`Are you sure you want to delete the entry for ${date}? This action cannot be undone.`)) {
      onDeleteEntry(id);
    }
  };

  const periodLabel = selectedMonth === 'last30' ? 'Last 30 Days' : formatMonth(selectedMonth);

  return (
    <div className="space-y-6 md:space-y-8 animate-fade-in pb-10">

      {/* Detail Modal */}
      {selectedEntry && (
        <CostSheetDetailsModal 
          entry={selectedEntry} 
          ingredients={ingredients} 
          onClose={() => setSelectedEntry(null)} 
        />
      )}

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white tracking-tight">{title}</h2>
          <p className="text-sm md:text-base text-slate-500 dark:text-slate-400 mt-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
            Overview for {periodLabel}
          </p>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-emerald-600 dark:text-emerald-400 group-hover:bg-emerald-100 dark:group-hover:bg-emerald-900/50 transition-colors">
              <span className="font-bold text-xl">৳</span>
            </div>
            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/30 px-2 py-1 rounded-md">~ Avg</span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Average Daily Cost</p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">৳{avgDailyCost.toLocaleString(undefined, { maximumFractionDigits: 0 })}</h3>
          </div>
        </div>

        {/* Average Per Head Cost Card */}
        <div className={`bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border hover:shadow-lg transition-all group relative overflow-hidden ${isAvgPerHeadHigh ? 'border-red-200 dark:border-red-900' : 'border-slate-200 dark:border-slate-700'}`}>
          {isAvgPerHeadHigh && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className={`p-3 rounded-xl transition-colors ${isAvgPerHeadHigh ? 'bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400' : 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50'}`}>
              <TrendingUp size={24} />
            </div>
             <span className="text-xs font-semibold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded-md">Target: ৳{targetPerHead}</span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Average Per Head Cost</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${isAvgPerHeadHigh ? 'text-red-600 dark:text-red-400' : 'text-slate-900 dark:text-white'}`}>
              ৳{avgPerHead.toFixed(2)}
            </h3>
            {isAvgPerHeadHigh && (
              <div className="mt-2 flex items-center gap-1.5 text-xs text-red-600 dark:text-red-400 font-medium">
                <AlertCircle size={12} />
                Exceeds Target by ৳{(avgPerHead - targetPerHead).toFixed(2)}
              </div>
            )}
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group">
           <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-violet-50 dark:bg-violet-900/30 rounded-xl text-violet-600 dark:text-violet-400 group-hover:bg-violet-100 dark:group-hover:bg-violet-900/50 transition-colors">
              <Users size={24} />
            </div>
            <span className="text-xs font-semibold text-violet-600 dark:text-violet-400 bg-violet-50 dark:bg-violet-900/30 px-2 py-1 rounded-md">~ Avg</span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Average Participants</p>
            <h3 className="text-2xl md:text-3xl font-bold text-slate-900 dark:text-white mt-1">{avgParticipants.toLocaleString()}</h3>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 p-5 md:p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 hover:shadow-lg transition-all group relative overflow-hidden">
          {lowStockItems.length > 0 && (
             <div className="absolute top-0 right-0 w-2 h-2 rounded-full bg-red-500 m-4 animate-ping"></div>
          )}
          <div className="flex justify-between items-start mb-4">
            <div className="p-3 bg-rose-50 dark:bg-rose-900/30 rounded-xl text-rose-600 dark:text-rose-400 group-hover:bg-rose-100 dark:group-hover:bg-rose-900/50 transition-colors">
              <AlertTriangle size={24} />
            </div>
             <span className={`text-xs font-semibold px-2 py-1 rounded-md ${lowStockItems.length > 0 ? 'text-rose-600 bg-rose-50 dark:text-rose-400 dark:bg-rose-900/30' : 'text-green-600 bg-green-50 dark:text-green-400 dark:bg-green-900/30'}`}>
               {lowStockItems.length > 0 ? 'Action Needed' : 'Healthy'}
             </span>
          </div>
          <div>
            <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Stock Alerts</p>
            <h3 className={`text-2xl md:text-3xl font-bold mt-1 ${lowStockItems.length > 0 ? 'text-rose-600 dark:text-rose-400' : 'text-slate-900 dark:text-white'}`}>{lowStockItems.length}</h3>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">

        {/* Cost Per Head Analysis Chart */}
        <div className="xl:col-span-2 bg-white dark:bg-slate-800 p-5 md:p-8 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 flex-wrap gap-4">
            <div>
              <h3 className="text-lg md:text-xl font-bold text-slate-900 dark:text-white">Cost Per Head Analysis</h3>
              <p className="text-xs md:text-sm text-slate-500 dark:text-slate-400">
                {selectedMonth === 'last30' ? '30-day performance trend' : `Analysis for ${formatMonth(selectedMonth)}`}
              </p>
            </div>

            {/* Filter Dropdown */}
            <div className="relative w-full md:w-auto">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Calendar size={16} className="text-slate-500 dark:text-slate-400" />
              </div>
              <select 
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(e.target.value)}
                className="w-full md:w-auto pl-10 pr-8 py-2 bg-slate-50 dark:bg-slate-700 border border-slate-200 dark:border-slate-600 text-slate-700 dark:text-slate-200 text-sm font-medium rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none appearance-none cursor-pointer hover:bg-slate-100 dark:hover:bg-slate-600 transition-colors"
              >
                <option value="last30">Last 30 Days</option>
                {availableMonths.map(month => (
                  <option key={month} value={month}>{formatMonth(month)}</option>
                ))}
              </select>
              <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                <Filter size={14} className="text-slate-400" />
              </div>
            </div>
          </div>

          <div className="h-[250px] md:h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={trendData} margin={{ top: 10, right: 0, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#334155" : "#f1f5f9"} />
                <XAxis 
                  dataKey="date" 
                  stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                  tick={{fontSize: 12}} 
                  tickLine={false}
                  axisLine={false}
                  dy={10}
                />
                <YAxis 
                  stroke={isDarkMode ? "#94a3b8" : "#94a3b8"} 
                  tick={{fontSize: 12}} 
                  tickFormatter={(val) => `৳${val}`} 
                  tickLine={false}
                  axisLine={false}
                />
                <Tooltip 
                  cursor={{fill: isDarkMode ? '#334155' : '#f1f5f9', opacity: 0.4}}
                  contentStyle={{ 
                    backgroundColor: isDarkMode ? '#1e293b' : '#fff', 
                    borderRadius: '12px', 
                    border: isDarkMode ? '1px solid #334155' : 'none',
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)'
                  }}
                  itemStyle={{ color: isDarkMode ? '#f8fafc' : '#1e293b', fontWeight: 600 }}
                  labelStyle={{ color: '#64748b', marginBottom: '4px' }}
                />
                <Bar 
                  dataKey="CostPerHead" 
                  fill="#3b82f6" 
                  radius={[4, 4, 0, 0]}
                  name="Per Head Cost (৳)"
                  maxBarSize={50}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Stock Alert List */}
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-md border border-slate-200 dark:border-slate-700 flex flex-col">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-6 flex items-center justify-between">
            <span className="flex items-center gap-2">
              Low Stock Warnings
            </span>
            <span className="text-xs font-normal text-slate-400 bg-slate-50 dark:bg-slate-700 px-2 py-1 rounded-full">{lowStockItems.length} Items</span>
          </h3>

          <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {lowStockItems.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center p-6 text-slate-400">
                <div className="w-12 h-12 bg-slate-50 dark:bg-slate-700 rounded-full flex items-center justify-center mb-3">
                   <AlertCircle size={20} />
                </div>
                <p className="text-sm">All inventory levels are healthy.</p>
              </div>
            ) : (
              lowStockItems.slice(0, 4).map(item => (
                <div key={item.id} className="group p-4 rounded-xl border border-slate-100 dark:border-slate-700 bg-white dark:bg-slate-800 hover:border-red-100 dark:hover:border-red-900 hover:bg-red-50/30 dark:hover:bg-red-900/10 transition-all">
                  <div className="flex justify-between items-start mb-2">
