import React, { useState, useEffect } from 'react';
import { HashRouter } from 'react-router-dom';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { DailyEntryForm } from './components/DailyEntryForm';
import { InventoryMasters } from './components/InventoryMasters';
import { AuditLog } from './components/AuditLog';
import { SystemSettings } from './components/SystemSettings';
import { Login } from './components/Login';
import { SupplierReport } from './components/SupplierReport';
import { Reporting } from './components/Reporting';
import { OFFICES } from './constants';
import { DailyEntry, Ingredient, UserRole, ActivityLog } from './types';
import { Menu, Loader2, Database } from 'lucide-react';
import { api } from './services/api';

function App() {
  // Authentication State
  const [userRole, setUserRole] = useState<UserRole | null>(() => {
    return sessionStorage.getItem('userRole') as UserRole | null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Theme State
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('theme');
    return savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  // App Data State
  const [entries, setEntries] = useState<DailyEntry[]>([]);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [activityHistory, setActivityHistory] = useState<ActivityLog[]>([]);
  const [offices] = useState(OFFICES);

  const [isLoading, setIsLoading] = useState(true);
  const [dataError, setDataError] = useState<string | null>(null);
  const [isConnected, setIsConnected] = useState(false);

  // Helper to log activity
  const handleLogActivity = async (action: any, details: string, metadata?: any) => {
    const log: ActivityLog = {
      id: `log_${Date.now()}`,
      timestamp: new Date().toISOString(),
      userRole: userRole || 'SYSTEM',
      action,
      details,
      metadata
    };

    // Update local state
    setActivityHistory(prev => [log, ...prev]);

    // Send to DB
    try {
      await api.logActivity(log);
    } catch (e) {
      console.error("Failed to log activity", e);
    }
  };

  // Initial Data Load
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        // Try to seed first (only runs if empty)
        await api.seedDatabase();

        const [fetchedIngredients, fetchedEntries, fetchedLogs] = await Promise.all([
          api.getIngredients(),
          api.getEntries(),
          api.getActivityLogs()
        ]);

        setIngredients(fetchedIngredients);
        setEntries(fetchedEntries);
        setActivityHistory(fetchedLogs);
        setDataError(null);
        setIsConnected(true);
      } catch (err: any) {
        console.error("Failed to load data from Supabase", err);
        // Fallback or error message
        setDataError("Could not connect to database. Please check your internet connection.");
        setIsConnected(false);
      } finally {
        setIsLoading(false);
      }
    };

    if (userRole) {
      loadData();
    }
  }, [userRole]);

  // Handle Login
  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    sessionStorage.setItem('userRole', role);
    handleLogActivity('LOGIN', `User logged in as ${role}`);
  };

  const handleLogout = () => {
    handleLogActivity('LOGOUT', `User ${userRole} logged out`);
    setUserRole(null);
    sessionStorage.removeItem('userRole');
    setActiveTab('dashboard');
    setIsConnected(false);
  };

  // Add Entry
  const handleAddEntry = async (newEntry: DailyEntry) => {
    // Optimistic Update
    setEntries(prev => [newEntry, ...prev]); // Add to top

    // Update Ingredients State locally
    const updatedIngredients = ingredients.map(ing => {
      const consumed = newEntry.itemsConsumed.find(c => c.ingredientId === ing.id);
      if (consumed) {
        return {
          ...ing,
          currentStock: Math.max(0, ing.currentStock - consumed.quantity),
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    // Redirect to correct dashboard based on entry type
    if (newEntry.officeId === 'events_main') {
        setActiveTab('events');
    } else {
        setActiveTab('dashboard');
    }

    handleLogActivity('CREATE_ENTRY', `Added Cost Sheet for ${newEntry.date}. Total: ৳${newEntry.totalCost}`, { entryId: newEntry.id });

    // Background Sync
    try {
      await api.addEntry(newEntry);
      // Update stock in DB for each consumed item
      for (const item of newEntry.itemsConsumed) {
        const ing = ingredients.find(i => i.id === item.ingredientId);
        if (ing) {
           const newStock = Math.max(0, ing.currentStock - item.quantity);
           await api.updateStock(ing.id, newStock);
        }
      }
    } catch (error) {
      console.error("Failed to sync new entry:", error);
      alert("Error saving to cloud. Data saved locally only.");
      setIsConnected(false);
    }
  };

  // Delete Entry
  const handleDeleteEntry = async (id: string) => {
    const entryToDelete = entries.find(e => e.id === id);
    if (!entryToDelete) return;

    // --- REVERT STOCK LOGIC ---
    // Create a copy of ingredients to update state
    const updatedIngredients = [...ingredients];

    // Iterate through consumed items and add them back to stock
    for (const item of entryToDelete.itemsConsumed) {
      const index = updatedIngredients.findIndex(i => i.id === item.ingredientId);
      if (index !== -1) {
        const ing = updatedIngredients[index];
        // Calculate new stock (Add back the consumed quantity)
        const newStock = Number((ing.currentStock + item.quantity).toFixed(3));

        // Update local array
        updatedIngredients[index] = {
          ...ing,
          currentStock: newStock,
          lastUpdated: new Date().toISOString()
        };

        // Sync Stock Reversion to DB
        try {
          await api.updateStock(ing.id, newStock);
        } catch (error) {
          console.error(`Failed to revert stock for ${ing.name}`, error);
        }
      }
    }

    // Update Ingredients State with reverted values
    setIngredients(updatedIngredients);

    // Remove the entry from the list
    setEntries(prev => prev.filter(e => e.id !== id));

    handleLogActivity('DELETE_ENTRY', `Deleted Cost Sheet for ${entryToDelete.date}. Stock reverted.`, { 
      deletedEntry: entryToDelete 
    });

    // Background Sync: Delete Entry
    try {
      await api.deleteEntry(id);
    } catch (error) {
      console.error("Failed to delete entry:", error);
      setIsConnected(false);
    }
  };

  // Restore Entry (Undo Delete)
  const handleRestoreEntry = async (restoredEntry: DailyEntry) => {
    if (entries.some(e => e.id === restoredEntry.id)) {
        alert("This entry already exists (it might have been restored already).");
        return;
    }

    if (!window.confirm(`Restore Cost Sheet for ${restoredEntry.date}? This will re-deduct items from stock.`)) {
        return;
    }

    // 1. Optimistic Add to List
    setEntries(prev => [restoredEntry, ...prev].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

    // 2. Consume Stock Again
    const updatedIngredients = ingredients.map(ing => {
      const consumed = restoredEntry.itemsConsumed.find(c => c.ingredientId === ing.id);
      if (consumed) {
        return {
          ...ing,
          currentStock: Math.max(0, ing.currentStock - consumed.quantity),
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    handleLogActivity('RESTORE_DATA', `Restored Cost Sheet for ${restoredEntry.date}. Stock re-deducted.`);

    // 3. Database Sync
    try {
        await api.restoreEntry(restoredEntry);
        // Deduct Stock in DB
        for (const item of restoredEntry.itemsConsumed) {
            const ing = ingredients.find(i => i.id === item.ingredientId);
            if (ing) {
               const newStock = Math.max(0, ing.currentStock - item.quantity);
               await api.updateStock(ing.id, newStock);
            }
        }
        alert("Entry restored successfully.");
    } catch (error) {
        console.error("Failed to restore entry:", error);
        alert("Failed to restore entry. Please check connection.");
        setIsConnected(false);
    }
  };

  // Stock Update
  const handleStockUpdate = async (id: string, quantity: number, type: 'add' | 'subtract', supplierName?: string) => {
    // Optimistic Update
    let newStockValue = 0;
    let itemName = '';

    const updatedIngredients = ingredients.map(ing => {
      if (ing.id === id) {
        itemName = ing.name;
        let newStock = ing.currentStock;
        if (type === 'add') {
          newStock += quantity;
        } else {
          newStock = Math.max(0, newStock - quantity);
        }
        newStockValue = Number(newStock.toFixed(3));

        return { 
          ...ing, 
          currentStock: newStockValue,
          supplierName: supplierName || ing.supplierName, // Update supplier if provided
          lastUpdated: new Date().toISOString()
        };
      }
      return ing;
    });
    setIngredients(updatedIngredients);

    const logDetails = `${type === 'add' ? 'Added' : 'Removed'} ${quantity} units for ${itemName}${supplierName ? ` (Supplier: ${supplierName})` : ''}`;
    handleLogActivity('UPDATE_STOCK', logDetails, { 
      ingredientId: id, quantity, type, supplier: supplierName 
    });

    // Background Sync
    try {
      await api.updateStock(id, newStockValue);
      // If supplier name was provided, update the master record for supplier
      if (supplierName) {
        await api.updateIngredientMaster(id, { supplierName });
      }
    } catch (error) {
      console.error("Failed to update stock:", error);
      setIsConnected(false);
    }
  };

  // Ingredient Master Update (Edit Details)
  const handleUpdateIngredient = async (id: string, updates: Partial<Ingredient>) => {
    // Optimistic Update
    const ingName = ingredients.find(i => i.id === id)?.name || 'Unknown Item';
    setIngredients(prev => prev.map(i => i.id === id ? { ...i, ...updates } : i));

    handleLogActivity('UPDATE_MASTER', `Updated master details for ${ingName}`, { updates });

    try {
      await api.updateIngredientMaster(id, updates);
    } catch (error) {
      console.error("Failed to update ingredient:", error);
      setIsConnected(false);
      // Revert optimization on error would ideally go here by fetching
    }
  };

  // Add New Ingredient
  const handleAddIngredient = async (newIngredient: Ingredient) => {
    // Optimistic Update with Sort
    setIngredients(prev => [...prev, newIngredient].sort((a, b) => a.name.localeCompare(b.name)));

    handleLogActivity('UPDATE_MASTER', `Added new ingredient: ${newIngredient.name}`, { newIngredient });

    try {
      await api.addIngredient(newIngredient);
    } catch (error) {
      console.error("Failed to add ingredient:", error);
      setIsConnected(false);
    }
  };

  // Ingredient Delete
  const handleDeleteIngredient = async (id: string) => {
    const ingName = ingredients.find(i => i.id === id)?.name || 'Unknown Item';
    // Optimistic Update
    setIngredients(prev => prev.filter(i => i.id !== id));

    handleLogActivity('UPDATE_MASTER', `Deleted ingredient: ${ingName}`, { deletedId: id });

    try {
      await api.deleteIngredient(id);
    } catch (error) {
      console.error("Failed to delete ingredient:", error);
      setIsConnected(false);
    }
  };

  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [activeTab]);

  return (
    <HashRouter>
      {!userRole ? (
        <Login onLogin={handleLogin} />
      ) : (
        <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 relative transition-colors duration-200">
          {/* Mobile Header */}
          <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-slate-900 text-white z-40 flex items-center px-4 shadow-md justify-between">
            <button 
              onClick={() => setIsMobileMenuOpen(true)}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors"
            >
              <Menu size={24} />
            </button>
            <span className="font-bold text-lg text-blue-400">ACI CANTEEN</span>
            <div className="w-8"></div>
          </div>

          {/* Mobile Overlay */}
          {isMobileMenuOpen && (
            <div 
              className="fixed inset-0 bg-black/50 z-40 md:hidden backdrop-blur-sm transition-opacity"
              onClick={() => setIsMobileMenuOpen(false)}
            />
          )}

          <Sidebar 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            isCollapsed={isSidebarCollapsed}
            toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            isMobileOpen={isMobileMenuOpen}
            setIsMobileOpen={setIsMobileMenuOpen}
            isDarkMode={isDarkMode}
            toggleDarkMode={toggleDarkMode}
            onLogout={handleLogout}
            userRole={userRole}
            isConnected={isConnected}
          />

          {/* Main Content */}
          <main 
            className={`flex-1 transition-all duration-300 
              ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} 
              ml-0 
              pt-16 md:pt-8 p-4 md:p-8 
              overflow-y-auto h-screen w-full
            `}
          >
            <div className="max-w-7xl mx-auto">
              {isLoading ? (
                <div className="flex flex-col items-center justify-center h-[60vh] text-slate-500">
                  <Loader2 size={48} className="animate-spin text-blue-500 mb-4" />
                  <p className="text-lg font-medium">Connecting to Database...</p>
                  <p className="text-sm">Fetching stock and history</p>
                </div>
              ) : dataError ? (
                <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 p-8 rounded-xl text-center">
                  <Database size={48} className="mx-auto text-red-500 mb-4" />
                  <h3 className="text-xl font-bold text-red-700 dark:text-red-300 mb-2">Connection Error</h3>
                  <p className="text-slate-600 dark:text-slate-300 mb-4">{dataError}</p>
                  <p className="text-sm text-slate-500">Make sure you have run the SQL script in Supabase Dashboard.</p>
                </div>
              ) : (
                <>
                  {activeTab === 'dashboard' && (
                    <Dashboard 
                      title="Executive Dashboard"
                      entries={entries.filter(e => e.officeId !== 'events_main')} 
                      offices={offices} 
                      ingredients={ingredients} 
                      isDarkMode={isDarkMode}
                      userRole={userRole}
                      onDeleteEntry={handleDeleteEntry}
                      onViewMasterStock={() => setActiveTab('masters')}
                      targetPerHead={72.72}
                    />
                  )}

                  {activeTab === 'events' && (
                    <Dashboard 
                      title="Events Cost Report"
                      entries={entries.filter(e => e.officeId === 'events_main')} 
                      offices={offices} 
                      ingredients={ingredients} 
                      isDarkMode={isDarkMode}
                      userRole={userRole}
                      onDeleteEntry={handleDeleteEntry}
                      onViewMasterStock={() => setActiveTab('masters')}
                      // Events might have a different target per head, setting high for now
                      targetPerHead={150}
                    />
                  )}

                  {activeTab === 'reports' && (
                    <Reporting 
                      entries={entries}
                      logs={activityHistory}
                      ingredients={ingredients}
                    />
                  )}

                  {activeTab === 'entry' && userRole === 'ADMIN' && (
                    <DailyEntryForm 
                      offices={offices} 
                      ingredients={ingredients} 
                      onAddEntry={handleAddEntry} 
                    />
                  )}

                  {activeTab === 'masters' && (
                    <InventoryMasters 
                      offices={offices} 
                      ingredients={ingredients}
                      onUpdateStock={handleStockUpdate}
                      userRole={userRole}
                      onUpdateIngredient={handleUpdateIngredient}
                      onDeleteIngredient={handleDeleteIngredient}
                    />
                  )}

                  {activeTab === 'suppliers' && (
                    <SupplierReport ingredients={ingredients} logs={activityHistory} />
                  )}

                  {activeTab === 'history' && userRole === 'ADMIN' && (
                    <AuditLog 
                      logs={activityHistory}
                      onRestoreEntry={handleRestoreEntry}
                    />
                  )}

                  {activeTab === 'settings' && (
                    <SystemSettings 
                      userRole={userRole} 
                      onAddIngredient={handleAddIngredient}
                    />
                  )}
                </>
              )}
            </div>
          </main>
        </div>
      )}
    </HashRouter>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell, PieChart, Pie 
} from 'recharts';
import { Calendar, Filter, Download, DollarSign, Users, TrendingUp, ShoppingBag, PieChart as PieIcon } from 'lucide-react';
import { DailyEntry, Ingredient, ActivityLog } from '../types';

interface ReportingProps {
  entries: DailyEntry[];
  logs: ActivityLog[];
  ingredients: Ingredient[];
}

type TimeFrame = 'week' | 'month' | 'quarter' | 'year' | 'custom';

export const Reporting: React.FC<ReportingProps> = ({ entries, logs, ingredients }) => {
  const [timeFrame, setTimeFrame] = useState<TimeFrame>('month');
  const [customStartDate, setCustomStartDate] = useState('');
  const [customEndDate, setCustomEndDate] = useState('');

  // --- 1. Date Filtering Logic ---
  const { startDate, endDate, label } = useMemo(() => {
    const end = new Date();
    let start = new Date();
    let lbl = '';

    if (timeFrame === 'custom') {
      return {
        startDate: customStartDate ? new Date(customStartDate) : new Date(0), // Fallback to epoch if empty
        endDate: customEndDate ? new Date(customEndDate) : new Date(),
        label: `${customStartDate} to ${customEndDate}`
      };
    }

    // Reset hours to start of day for comparison
    end.setHours(23, 59, 59, 999);
    start.setHours(0, 0, 0, 0);

    switch (timeFrame) {
      case 'week':
        start.setDate(end.getDate() - 7);
        lbl = 'Last 7 Days';
        break;
      case 'month':
        start.setDate(1); // Start of current month
        lbl = 'This Month';
        break;
      case 'quarter':
        start.setMonth(Math.floor(end.getMonth() / 3) * 3);
        start.setDate(1);
        lbl = 'This Quarter';
        break;
      case 'year':
        start.setMonth(0, 1);
        lbl = 'This Year';
        break;
    }

    return { startDate: start, endDate: end, label: lbl };
  }, [timeFrame, customStartDate, customEndDate]);

  // --- 2. Filter Data ---
  const filteredEntries = useMemo(() => {
    return entries.filter(e => {
      const d = new Date(e.date);
      return d >= startDate && d <= endDate;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [entries, startDate, endDate]);

  const filteredPurchases = useMemo(() => {
    return logs.filter(l => {
        const d = new Date(l.timestamp);
        // Filter for ADD stock actions only
        return l.action === 'UPDATE_STOCK' && 
               l.metadata?.type === 'add' && 
               l.metadata?.quantity > 0 &&
               d >= startDate && 
               d <= endDate;
    });
  }, [logs, startDate, endDate]);

  // --- 3. Calculate Consumption Metrics ---
  const consumptionStats = useMemo(() => {
    const totalCost = filteredEntries.reduce((sum, e) => sum + e.totalCost, 0);
    const totalParticipants = filteredEntries.reduce((sum, e) => sum + e.participantCount, 0);
    const daysCount = filteredEntries.length || 1;

    return {
        totalCost,
        totalParticipants,
        avgCostPerHead: totalParticipants > 0 ? totalCost / totalParticipants : 0,
        avgDailyCost: totalCost / daysCount,
        avgDailyParticipants: Math.round(totalParticipants / daysCount)
    };
  }, [filteredEntries]);

  // --- 4. Calculate Vendor/Purchase Metrics ---
  const purchaseStats = useMemo(() => {
    let totalPurchaseEst = 0;
    const vendorMap: Record<string, number> = {};

    filteredPurchases.forEach(log => {
        const ing = ingredients.find(i => i.id === log.metadata.ingredientId);
        // Snapshot price estimation (using current master price)
        const cost = (log.metadata.quantity || 0) * (ing?.unitPrice || 0);

        // Determine supplier
        const supplier = log.metadata.supplier || ing?.supplierName || 'Unassigned / Local Market';

        totalPurchaseEst += cost;
        vendorMap[supplier] = (vendorMap[supplier] || 0) + cost;
    });

    const vendorData = Object.entries(vendorMap)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value); // Sort highest spend first

    return {
        totalPurchaseEst,
        vendorData
    };
  }, [filteredPurchases, ingredients]);

  // --- 5. Chart Data Prep ---
  const dailyTrendData = useMemo(() => {
    return filteredEntries.map(e => ({
        date: new Date(e.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' }),
        fullDate: e.date,
        Cost: e.totalCost,
        Participants: e.participantCount,
        PerHead: e.participantCount ? Number((e.totalCost / e.participantCount).toFixed(2)) : 0
    }));
  }, [filteredEntries]);

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#6366f1'];

  // --- 6. Export Function ---
  const handleExportReport = () => {
    const csvRows = [];

    // Header / Summary
    csvRows.push(['REPORT SUMMARY']);
    csvRows.push(['Report Type', 'Canteen Analytics (Events Excluded)']);
    csvRows.push(['Period', label]);
    csvRows.push(['Start Date', startDate.toLocaleDateString()]);
    csvRows.push(['End Date', endDate.toLocaleDateString()]);
    csvRows.push([]);

    csvRows.push(['KEY METRICS']);
    csvRows.push(['Total Consumption Cost', consumptionStats.totalCost.toFixed(2)]);
    csvRows.push(['Total Participants', consumptionStats.totalParticipants]);
    csvRows.push(['Avg Cost Per Head', consumptionStats.avgCostPerHead.toFixed(2)]);
    csvRows.push(['Avg Daily Cost', consumptionStats.avgDailyCost.toFixed(2)]);
    csvRows.push(['Total Purchase Est.', purchaseStats.totalPurchaseEst.toFixed(2)]);
    csvRows.push([]);

    // Vendor Section
    csvRows.push(['VENDOR / SUPPLIER ANALYSIS']);
    csvRows.push(['Supplier Name', 'Total Purchase Amount (Est.)']);
    purchaseStats.vendorData.forEach(v => {
        csvRows.push([`"${v.name.replace(/"/g, '""')}"`, v.value.toFixed(2)]);
    });
    csvRows.push([]);

    // Daily Breakdown
    csvRows.push(['DAILY CONSUMPTION BREAKDOWN']);
    csvRows.push(['Date', 'Participants', 'Total Cost', 'Cost Per Head', 'Menu']);
    filteredEntries.forEach(e => {
        const ph = e.participantCount ? (e.totalCost / e.participantCount).toFixed(2) : "0.00";
        csvRows.push([
            e.date,
            e.participantCount,
            e.totalCost.toFixed(2),
            ph,
            `"${(e.menuDescription || '').replace(/"/g, '""')}"`
        ]);
    });

    const csvContent = csvRows.map(e => e.join(',')).join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `ACI_Canteen_Report_${timeFrame}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-12">
        {/* Header & Controls */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4 border-b border-slate-200 dark:border-slate-700 pb-6">
            <div>
                <h2 className="text-3xl font-bold text-slate-900 dark:text-white flex items-center gap-3">
                    <PieIcon className="text-blue-600 dark:text-blue-400" size={32} />
                    Analytics & Reporting
                </h2>
                <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">
                    Generate comprehensive reports on costs, consumption, and supplier performance.
                </p>
            </div>

            <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3 w-full xl:w-auto">
                {timeFrame === 'custom' && (
                    <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1 rounded-lg border border-slate-300 dark:border-slate-600">
                        <input 
                            type="date" 
                            value={customStartDate}
                            onChange={(e) => setCustomStartDate(e.target.value)}
                            className="bg-transparent text-sm p-1 outline-none text-slate-700 dark:text-slate-200"
                        />
                        <span className="text-slate-400">-</span>
                        <input 
                            type="date" 
                            value={customEndDate}
                            onChange={(e) => setCustomEndDate(e.target.value)}
                            className="bg-transparent text-sm p-1 outline-none text-slate-700 dark:text-slate-200"
                        />
                    </div>
                )}

                <div className="flex items-center bg-slate-100 dark:bg-slate-800 p-1 rounded-lg border border-slate-200 dark:border-slate-700">
                    <button 
                        onClick={() => setTimeFrame('week')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'week' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Week
                    </button>
                    <button 
                        onClick={() => setTimeFrame('month')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'month' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Month
                    </button>
                    <button 
                        onClick={() => setTimeFrame('quarter')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'quarter' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Quarter
                    </button>
                    <button 
                        onClick={() => setTimeFrame('year')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'year' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Year
                    </button>
                    <button 
                        onClick={() => setTimeFrame('custom')}
                        className={`px-3 py-1.5 text-sm font-medium rounded-md transition-all ${timeFrame === 'custom' ? 'bg-white dark:bg-slate-700 shadow text-blue-600 dark:text-blue-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                        Custom
                    </button>
                </div>

                <button 
                    onClick={handleExportReport}
                    className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 dark:shadow-blue-900/50 transition-colors"
                >
                    <Download size={18} /> Export Report
                </button>
            </div>
        </div>

        {/* Date Context Bar */}
        <div className="bg-blue-50 dark:bg-blue-900/20 px-4 py-2 rounded-lg border border-blue-100 dark:border-blue-800 flex items-center gap-2 text-blue-700 dark:text-blue-300 text-sm font-medium">
            <Calendar size={16} />
            Showing data for: <span className="font-bold">{startDate.toLocaleDateString()} - {endDate.toLocaleDateString()}</span>
        </div>

        {/* --- KPI CARDS --- */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Total Consumption</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{consumptionStats.totalCost.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                        </h3>
                    </div>
                    <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-xl text-blue-600 dark:text-blue-400">
                        <DollarSign size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Operational expense for selected period
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Total Participants</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            {consumptionStats.totalParticipants.toLocaleString()}
                        </h3>
                    </div>
                    <div className="p-3 bg-violet-50 dark:bg-violet-900/30 rounded-xl text-violet-600 dark:text-violet-400">
                        <Users size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Avg. {consumptionStats.avgDailyParticipants} per day
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Avg Cost Per Head</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{consumptionStats.avgCostPerHead.toFixed(2)}
                        </h3>
                    </div>
                    <div className="p-3 bg-emerald-50 dark:bg-emerald-900/30 rounded-xl text-emerald-600 dark:text-emerald-400">
                        <TrendingUp size={20} />
                    </div>
                </div>
                <div className="mt-3 text-xs text-slate-400">
                    Global average for period
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700">
                <div className="flex justify-between items-start">
                    <div>
                        <p className="text-sm font-medium text-slate-500 dark:text-slate-400">Purchase Est.</p>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white mt-1">
                            ৳{purchaseStats.totalPurchaseEst.toLocaleString(undefined, { maximumFractionDigits: 0 })}
